  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);

  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const formatRoleLabelShort = (role: Role) => {
    switch(role) {
        case Role.CLASH: return "CLASH";
        case Role.JUNGLE: return "JUNGLE";
        case Role.MID: return "MID";
        case Role.FARM: return "FARM";
        case Role.ROAM: return "ROAM";
        case Role.COACH: return "COACH";
        default: return (role as string).toUpperCase();
    }
  };

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    if (window.confirm("Are you sure you want to reveal all players and skip animations?")) {
        const allCards = new Set<string>();
        displayRoles.forEach(r => {
          allCards.add(getCardId('azure', r));
          allCards.add(getCardId('crimson', r));
        });
        setRevealedCards(allCards);
        setCurrentRoleIndex(displayRoles.length);
    }
  };

  const handleAbort = () => {
    if (window.confirm("Are you sure you want to abort the current draft? All progress will be lost.")) {
      onReset();
    }
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    match.azureTeam.forEach(slot => { if (revealedCards.has(getCardId('azure', slot.role))) revealedPlayerIds.add(slot.player.id); });
    match.crimsonTeam.forEach(slot => { if (revealedCards.has(getCardId('crimson', slot.role))) revealedPlayerIds.add(slot.player.id); });

    const candidates = activePlayers
      .filter(p => {
          if (revealedPlayerIds.has(p.id)) return false;
          if (role === Role.COACH) return p.roles.includes(Role.COACH);
          return p.isAllRoles || p.roles.includes(role);
      });

    const candidateNames = candidates.map(p => p.name);

    if (candidates.length === 1) {
        const cardId = getCardId(team, role);
        setAutoFillFlash(cardId);
        setRevealedCards(prev => new Set(prev).add(cardId));
        if (team === 'crimson') {
            setCurrentRoleIndex(prev => prev + 1);
        }
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    if (!candidateNames.includes(winner.name)) {
        candidateNames.push(winner.name);
    }

    const randomDuration = Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000;

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates: candidateNames,
      duration: randomDuration
    });
  };

  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return p.roles.includes(Role.COACH);
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    if (candidates.length === 1) {
        onReroll(team, role, candidates[0]);
        return;
    }

    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000; 

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const handleWheelCancel = () => setWheelState(null);
  const handleInitializeBattle = () => setViewState('transition');
  const handleTransitionComplete = () => { onStartBattle(); setViewState('final'); };
  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) { setWinningTeam(winner); setViewState('celebration'); } 
    else { onCompleteMatch(null); }
  };
  const handleCelebrationDismiss = () => setViewState('evaluation');
  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => { onCompleteMatch(winningTeam, mvpId, ratings); }

  if (viewState === 'evaluation' && winningTeam) return <EvaluationScreen match={match} winner={winningTeam} onComplete={handleEvaluationComplete} />;
  if (viewState === 'celebration' && winningTeam) return <VictoryCelebration winner={winningTeam} teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} onDismiss={handleCelebrationDismiss} />;
  if (viewState === 'transition') return <PortalTransition azureTeam={match.azureTeam} crimsonTeam={match.crimsonTeam} onComplete={handleTransitionComplete} />;
  if (viewState === 'final') return <MatchSummary match={match} onReset={handleMatchDecided} />;

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const cardId = getCardId(team, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.8)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : team === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-hok-cyan', glow: 'shadow-[0_0_10px_#00d2ff]', text: 'text-hok-cyan', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-hok-red', glow: 'shadow-[0_0_10px_#ef4444]', text: 'text-hok-red', gradient: 'from-[#c02d2d]/20 to-transparent' };

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-90 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${isAutoFilled ? 'shadow-[0_0_30px_#dcb06b] border-[#dcb06b]' : theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-1 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-0.5 px-2 py-0.5 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block scale-90 origin-${team === 'crimson' ? 'right' : 'left'}`}>
                {RoleIcons[role]}
             </div>
             <span className={`block text-lg md:text-xl font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>
             {isAutoFilled && (
                 <div className="absolute top-1 right-2 text-[8px] text-[#dcb06b] font-black uppercase tracking-tighter animate-pulse">Auto-Assigned</div>
             )}
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className={`absolute top-1 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20 ${team === 'azure' ? 'right-2' : 'left-2'}`}
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     const nextTeam = !revealedCards.has(getCardId('azure', nextRoleName)) ? 'AZURE' : 'CRIMSON';
     const roleLabel = formatRoleLabelShort(nextRoleName);
     buttonText = `SELECT ${nextTeam} ${roleLabel}`;
  }

  return (
    <>
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates} 
          winnerName={wheelState.winnerName} 
          team={wheelState.team} 
          roleName={wheelState.role} 
          roomId={match.roomId} 
          duration={wheelState.duration}
          onComplete={handleWheelComplete} 
          onCancel={handleWheelCancel} 
        />
      )}
      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={handleAbort} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" /></svg> ABORT DRAFT</span>
           </Button>
           {!isFinished && <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">SKIP ALL</Button>}
        </div>

        {/* PRESTIGE NEON ROOM ID MATCH DISPLAY */}
        <div className="flex flex-col items-center mb-8 pt-8">
           <div className="flex flex-col items-center gap-1">
              <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase drop-shadow-sm mb-1">ROOM ID</span>
              <div className="relative">
                 <div className="absolute -inset-6 bg-[#dcb06b] blur-[30px] opacity-20 animate-pulse pointer-events-none"></div>
                 <div className="relative bg-black/80 border-2 border-[#dcb06b] px-16 py-4 clip-corner-sm flex flex-col items-center shadow-[0_0_40px_rgba(220,176,107,0.4)] transition-all">
                    <span className="text-4xl md:text-5xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_20px_#dcb06b] animate-[chromatic_0.2s_infinite]">
                      {match.roomId}
                    </span>
                 </div>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl mt-12">
              <div className="w-1/3 text-center"><h2 className="text-xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600">AZURE GOLEM TEAM</h2></div>
              <div className="w-1/3 flex justify-center"><div className="relative w-20 h-20 flex items-center justify-center"><span className="text-3xl font-black italic text-[#dcb06b] z-10 animate-pulse-fast">VS</span></div></div>
              <div className="w-1/3 text-center"><h2 className="text-xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600">CRIMSON GOLEM TEAM</h2></div>
           </div>
        </div>

        <div className="relative space-y-2 md:space-y-3">
          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-8 items-center">
               <div className="order-1 md:order-none">{renderPlayerCard(role, idx, 'azure')}</div>
               <div className="order-2 md:order-none">{renderPlayerCard(role, idx, 'crimson')}</div>
            </div>
          ))}
        </div>
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end bg-gradient-to-t from-[#05090f] via-[#05090f]/90 to-transparent h-48 pointer-events-none">
           <div className="pointer-events-auto">
              {!isFinished ? (
                 <button onClick={handleNext} className="group relative px-12 h-16 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-lg hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_20px_rgba(220,176,107,0.2)]">
                   {buttonText}
                 </button>
              ) : (
                 <Button onClick={handleInitializeBattle} className="px-12 animate-pulse">INITIALIZE BATTLE</Button>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {rating === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500">
           {rating === -2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  const gridClasses = isSidebarOpen ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => setFilter(val as FilterType)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-3 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';

          // High Priority: MVP/Coach Borders
          if (player.isActive) {
            if (isMvp) {
              glowColor = 'drop-shadow-[0_0_10px_#fbbf24]';
              animationLayer = <div className="absolute inset-[-100%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>;
            } else if (isCoach) {
              glowColor = 'drop-shadow-[0_0_10px_white]';
              animationLayer = <div className="absolute inset-[-100%] bg-[conic-gradient(from_0deg,transparent_0deg,white_90deg,transparent_180deg,white_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>;
            } else if (ws >= 2) {
              // Win Streak Hierarchy
              let wsColor = '#00d2ff'; // WS 2: Biru
              if (ws >= 5) wsColor = '#ef4444'; // WS 5: Merah
              else if (ws >= 4) wsColor = '#f97316'; // WS 4: Oren
              else if (ws >= 3) wsColor = '#a855f7'; // WS 3: Ungu

              glowColor = `drop-shadow-[0_0_8px_${wsColor}]`;
              animationLayer = <div className="absolute inset-[-100%]" style={{ background: `conic-gradient(from 0deg, transparent 0deg, ${wsColor} 120deg, transparent 180deg, ${wsColor} 300deg, transparent 360deg)` }} className="animate-[spin_3s_linear_infinite] opacity-100"></div>;
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]">
                 {animationLayer}
              </div>
              <div className={`absolute inset-[1px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/50 grayscale'}`}>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase ${getRoleBadgeStyle(r)}`}>{r.split(' ')[0]}</span>)
                      )}
                    </div>
                  </div>
                  <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b]"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg></button>
                </div>

                {ws > 1 && player.isActive && (
                  <div className="absolute top-0 right-8 px-1.5 py-0.5 text-[7px] font-black uppercase tracking-wider bg-black/80 text-white border border-white/20 clip-corner-sm flex items-center gap-1">
                    <span className="animate-pulse">🔥</span> {ws} WS
                  </div>
                )}

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => onToggleActive(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => onEdit(players.find(p => p.id === menuOpenId)!)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => onRemove(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);

  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => {
        setIsLoading(false);
    }, 2500);

    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => {
            setElapsedSeconds(prev => prev + 1);
        }, 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); 
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     const type = e.dataTransfer.getData("type");
     if (type === "mvp-token") {
        setMvpId(playerId);
     }
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = 0;
          if (current <= 0) next = 1;
          else if (current === 1) next = 2;
          else next = 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = 0;
        if (current >= 0) next = -1;
        else if (current === -1) next = -2;
        else next = 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.2em] animate-pulse">CALCULATING BATTLE DATA</h2>
            <div className="w-64 h-1 bg-[#1e3a5f] mt-4 rounded overflow-hidden">
                <div className="h-full bg-[#dcb06b] animate-[loading-bar_2s_ease-in-out_infinite]"></div>
            </div>
        </div>
    );
  }

  const MVPToken = () => (
    <div 
      draggable 
      onDragStart={handleDragStart}
      className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"
    >
       <div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white animate-pulse">
           <span className="font-black italic text-[#05090f] text-xs">MVP</span>
       </div>
    </div>
  );

  const winningTeam = winner === 'azure' ? match.azureTeam : match.crimsonTeam;
  const losingTeam = winner === 'azure' ? match.crimsonTeam : match.azureTeam;
  const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

  const renderTeamColumn = (teamSlots: typeof winningTeam, teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';

      return (
        <div className={`flex-1 w-full border ${borderColor} ${bgColor} p-0 clip-corner-md transition-all`}>
            <div className={`p-4 bg-opacity-30 border-b border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <div className="flex items-center gap-2">
                    <div className={`w-1 h-6 ${teamColor === 'cyan' ? 'bg-cyan-500' : 'bg-red-500'}`}></div>
                    <h3 className={`${textColor} font-cinzel font-bold text-xl`}>{teamName}</h3>
                </div>
                {isWinner && <span className="text-[#dcb06b] font-bold uppercase tracking-widest text-xs border border-[#dcb06b] px-2 py-1 rounded">Victory</span>}
            </div>

            <div className="p-4 space-y-2">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div 
                            key={role} 
                            onDragOver={!isCoach ? handleDragOver : undefined}
                            onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined}
                            className={`
                                flex items-center justify-between bg-[#0a1a2f]/50 p-3 rounded border relative overflow-hidden group transition-all
                                ${isMvp ? 'border-yellow-400 shadow-[0_0_15px_rgba(251,191,36,0.3)]' : isCoach ? 'border-white/20 bg-white/5' : 'border-white/5 hover:border-white/20'}
                            `}
                        >
                            <div className="flex items-center gap-4 relative z-10 flex-1 min-w-0">
                                <div className={`shrink-0 ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-500/50' : 'text-red-500/50')}`}>
                                    {RoleIcons[role]}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <div className={`text-lg font-orbitron truncate ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                            </div>
                            <div className="flex items-center gap-4 relative z-10 shrink-0">
                                {match.isCoachMode && (
                                    <div className="flex flex-col gap-1 mr-2 items-center">
                                        <button onClick={() => cycleRatingUp(slot.player.id)} className={`p-1 rounded hover:bg-white/10 ${rating > 0 ? 'text-green-400' : 'text-gray-600'}`}>
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
                                        </button>
                                        <button onClick={() => cycleRatingDown(slot.player.id)} className={`p-1 rounded hover:bg-white/10 ${rating < 0 ? 'text-red-500' : 'text-gray-600'}`}>
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
                                        </button>
                                    </div>
                                )}
                                {!isCoach && (
                                    <div className="w-10 h-10 flex items-center justify-center">
                                        {isMvp ? (
                                            <div className="w-8 h-8 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px]">MVP</div>
                                        ) : (
                                            <div className="w-8 h-8 border border-dashed border-white/10 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="relative z-10 w-full max-w-6xl animate-slide-in h-full overflow-y-auto py-8">
          <div className="text-center mb-6">
             <h1 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase mb-1">Evaluation</h1>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest uppercase mb-1">Session Duration</span>
                <div className="text-2xl font-mono font-bold text-white bg-black/50 px-6 py-1 rounded border border-[#dcb06b]/20">
                  {formatTime(elapsedSeconds)}
                </div>
             </div>
          </div>
          <div className="flex flex-col items-center mb-8">
             {!mvpId ? <MVPToken /> : <button onClick={() => setMvpId('')} className="text-xs text-red-400 underline uppercase tracking-widest">Reset MVP</button>}
          </div>
          <div className="flex flex-col md:flex-row gap-8 items-start justify-center">
             {renderTeamColumn(match.azureTeam, "AZURE GOLEM TEAM", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM TEAM", winner === 'crimson', 'red')}
          </div>
          <div className="mt-12 flex justify-center pb-8">
             <Button onClick={() => onComplete(mvpId, ratings)} className="px-16 py-4 text-xl shadow-[0_0_20px_#dcb06b]">FINISH EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {rating === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500">
           {rating === -2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  const gridClasses = isSidebarOpen ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => setFilter(val as FilterType)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-3 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';

          // High Priority: MVP/Coach Borders
          if (player.isActive) {
            if (isMvp) {
              glowColor = 'drop-shadow-[0_0_10px_#fbbf24]';
              animationLayer = <div className="absolute inset-[-100%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>;
            } else if (isCoach) {
              glowColor = 'drop-shadow-[0_0_10px_white]';
              animationLayer = <div className="absolute inset-[-100%] bg-[conic-gradient(from_0deg,transparent_0deg,white_90deg,transparent_180deg,white_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>;
            } else if (ws >= 2) {
              // Win Streak Hierarchy
              let wsColor = '#00d2ff'; // WS 2: Biru
              if (ws >= 5) wsColor = '#ef4444'; // WS 5: Merah
              else if (ws >= 4) wsColor = '#f97316'; // WS 4: Oren
              else if (ws >= 3) wsColor = '#a855f7'; // WS 3: Ungu

              glowColor = `drop-shadow-[0_0_8px_${wsColor}]`;
              // Fix: Merged duplicate className attributes
              animationLayer = <div style={{ background: `conic-gradient(from 0deg, transparent 0deg, ${wsColor} 120deg, transparent 180deg, ${wsColor} 300deg, transparent 360deg)` }} className="absolute inset-[-100%] animate-[spin_3s_linear_infinite] opacity-100"></div>;
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]">
                 {animationLayer}
              </div>
              <div className={`absolute inset-[1px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/50 grayscale'}`}>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase ${getRoleBadgeStyle(r)}`}>{r.split(' ')[0]}</span>)
                      )}
                    </div>
                  </div>
                  <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b]"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg></button>
                </div>

                {ws > 1 && player.isActive && (
                  <div className="absolute top-0 right-8 px-1.5 py-0.5 text-[7px] font-black uppercase tracking-wider bg-black/80 text-white border border-white/20 clip-corner-sm flex items-center gap-1">
                    <span className="animate-pulse">🔥</span> {ws} WS
                  </div>
                )}

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => onToggleActive(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => onEdit(players.find(p => p.id === menuOpenId)!)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => onRemove(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { generateMatch } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';

const HOK_HEROES = [
  { name: "Arthur", roles: [Role.CLASH] },
  { name: "Sun Ce", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Kaizer", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Biron", roles: [Role.CLASH] },
  { name: "Li Xin", roles: [Role.CLASH] },
  { name: "Charlotte", roles: [Role.CLASH] },
  { name: "Lam", roles: [Role.JUNGLE] },
  { name: "Prince of Lanling", roles: [Role.JUNGLE, Role.ROAM] },
  { name: "Wukong", roles: [Role.JUNGLE] },
  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

type ViewMode = 'lobby' | 'match' | 'battle';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  const navigate = useCallback((mode: ViewMode, data: any) => {
    setViewMode(mode);
    if (mode === 'lobby' && Array.isArray(data)) setPlayers(data);
    else if ((mode === 'match' || mode === 'battle') && data) setCurrentMatch(data);
  }, []);

  const handleBatchProcess = (batchData: { name: string; roles: Role[]; isAllRoles: boolean; action?: 'add' | 'bench' }[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], roles: item.roles, isAllRoles: item.isAllRoles, isActive: true };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };
  const handleUpdatePlayer = (updatedPlayer: Player) => setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) { setErrorMsg("Please enter a Room ID."); return; }
    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) { setErrorMsg(`Need ${required} ACTIVE players. Current: ${activePlayers.length}`); return; }
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) { setCurrentMatch(result); setErrorMsg(null); navigate('match', result); }
    else { setErrorMsg("Failed to find valid composition."); }
  };

  const handleClearAll = () => { if (window.confirm("Clear all players from the roster?")) setPlayers([]); };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;
    const updatedMatch = {
        ...currentMatch,
        azureTeam: currentMatch.azureTeam.map(slot => (team === 'azure' && slot.role === role) ? { ...slot, player: newPlayer } : slot),
        crimsonTeam: currentMatch.crimsonTeam.map(slot => (team === 'crimson' && slot.role === role) ? { ...slot, player: newPlayer } : slot)
    };
    setCurrentMatch(updatedMatch); navigate('match', updatedMatch);
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);

    const azureIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
    const crimsonIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));
    const allMatchIds = new Set([...azureIds, ...crimsonIds]);

    const updatedPlayers = players.map(p => {
      let isLastMatchMvp = mvpId === p.id;
      if (!allMatchIds.has(p.id)) return { ...p, isLastMatchMvp: false };

      const isAzure = azureIds.has(p.id);
      const isWinner = winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson'));
      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };

      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }

      return { 
        ...p, 
        stats: newStats, 
        isLastMatchMvp, 
        lastMatchRating: ratings?.[p.id] || 0 
      };
    });

    setPlayers(updatedPlayers); 
    navigate('lobby', updatedPlayers);
    setCurrentMatch(null); 
    setRoomId('');
  };

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const batchData = shuffledHeroes.slice(0, 15).map(hero => ({ name: hero.name, roles: hero.roles, isAllRoles: false, action: 'add' as const }));
     for(let i=0; i<5; i++) batchData.push({ name: `Flex Player ${i+1}`, roles: [], isAllRoles: true, action: 'add' });
     if (isCoachMode) {
        batchData.push({ name: "Coach Gemik", roles: [Role.COACH], isAllRoles: false, action: 'add' });
        batchData.push({ name: "Coach KPL", roles: [Role.COACH], isAllRoles: false, action: 'add' });
     }
     handleBatchProcess(batchData);
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />}

      {viewMode === 'lobby' && (
        <>
          <header className="sticky top-0 z-50 h-16 flex items-center justify-center border-b border-[#dcb06b]/20 bg-[#05090f]/90 backdrop-blur-md shadow-lg">
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[#dcb06b]/5 to-transparent"></div>
            <div className="flex items-center gap-3 animate-float">
               <div className="w-8 h-8 border-2 border-[#dcb06b] rotate-45 flex items-center justify-center bg-[#0a1a2f] shadow-[0_0_10px_#dcb06b]">
                  <div className="w-4 h-4 bg-[#dcb06b]"></div>
               </div>
               <h1 className="text-2xl font-cinzel font-black tracking-[0.2em] text-white">
                 <span className="hok-gold-text">HONOR</span> OF <span className="hok-gold-text">KINGS</span>
               </h1>
            </div>
          </header>

          <main className="relative z-10 pt-8 px-4 flex-grow max-w-7xl mx-auto w-full">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              <div className={`lg:col-span-4 space-y-6 ${isSidebarOpen ? '' : 'hidden'}`}>

                {/* PRESTIGE NEON ROOM ID LOBBY */}
                <div className="flex flex-col items-center gap-2 mb-4">
                   <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase drop-shadow-sm">Room ID</span>
                   <div className="relative w-full max-w-[180px]">
                      <div className="absolute -inset-4 bg-[#dcb06b] blur-[20px] opacity-15 animate-pulse pointer-events-none"></div>
                      <div className="relative bg-black/80 border-2 border-[#dcb06b] py-3 px-4 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                         <input 
                            type="text" 
                            value={roomId} 
                            onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} 
                            placeholder="0000" 
                            className={`bg-transparent text-4xl font-orbitron font-black w-full text-center focus:outline-none tracking-[0.4em] transition-all duration-300
                              ${roomId ? 'text-white drop-shadow-[0_0_15px_#dcb06b] animate-[chromatic_0.2s_infinite]' : 'text-[#4a5f78] opacity-60'}
                              placeholder-[#4a5f78]`}
                         />
                      </div>
                   </div>
                </div>

                {/* COACH MODE BUTTON */}
                <button 
                  onClick={() => setIsCoachMode(!isCoachMode)}
                  className="relative w-full group overflow-hidden p-[3px] clip-corner-sm transition-all duration-300 transform hover:scale-[1.02] active:scale-[0.98]"
                >
                   {isCoachMode && (
                     <div className="absolute inset-[-100%] transition-opacity duration-700">
                        <div className="absolute inset-0 bg-[conic-gradient(from_0deg,transparent_0deg,#dcb06b_60deg,#f3dcb1_120deg,transparent_180deg,#dcb06b_240deg,#f3dcb1_300deg,transparent_360deg)] animate-[spin_3s_linear_infinite]"></div>
                     </div>
                   )}
                   <div className={`
                      relative z-10 py-5 px-6 flex items-center justify-center transition-all duration-300 clip-corner-sm border
                      ${isCoachMode 
                          ? 'bg-black text-[#dcb06b] border-transparent shadow-[inset_0_0_20px_rgba(220,176,107,0.5)]' 
                          : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}
                   `}>
                      <span className={`font-cinzel font-black text-sm tracking-[0.3em] uppercase transition-all duration-500 ${isCoachMode ? 'text-white drop-shadow-[0_0_10px_#dcb06b]' : ''}`}>
                         COACH MODE {isCoachMode ? 'ENABLED' : 'DISABLED'}
                      </span>
                   </div>
                </button>

                <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} />

                <div className="relative p-6 clip-corner-md bg-gradient-to-b from-[#1a2c42] to-[#05090f] border border-[#dcb06b]/20">
                   <div className="flex justify-between items-end mb-6">
                      <div>
                         <div className="text-[#8a9db8] text-[10px] uppercase font-bold mb-1">Active Players</div>
                         <div className="text-5xl font-orbitron font-bold text-white">{activePlayers.length}</div>
                      </div>
                      <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors">Quick Fill</button>
                   </div>
                   {errorMsg && <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">{errorMsg}</div>}
                   <Button onClick={handleGenerate} className="w-full" disabled={activePlayers.length < (isCoachMode ? 12 : 10)}>START MATCHMAKING</Button>
                </div>
              </div>

              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex items-center justify-between mb-6">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 border border-[#1e3a5f] text-[#dcb06b] bg-[#0a1a2f]/50 transition-all">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
                    </button>
                    <h2 className="text-2xl font-cinzel font-black text-[#dcb06b]">SQUAD ROSTER</h2>
                    <button onClick={handleClearAll} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase transition-colors">Clear All</button>
                 </div>
                 <div className="tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px]">
                    <PlayerList players={players} onRemove={removePlayer} onToggleActive={togglePlayerActive} onEdit={handleEditPlayer} isSidebarOpen={isSidebarOpen} />
                 </div>
                 <div className="mt-12 tech-border p-6 bg-[#0a1a2f]/40">
                    <h2 className="text-2xl font-cinzel font-black text-[#dcb06b] mb-6">BATTLE HISTORY</h2>
                    <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} />
                 </div>
              </div>
            </div>
          </main>

          <footer className="py-12 px-6 text-center border-t border-[#dcb06b]/10 bg-[#05090f] mt-auto">
              <div className="max-w-4xl mx-auto flex flex-col items-center gap-4">
                  <div className="w-12 h-0.5 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent mb-2"></div>
                  <div className="text-[#dcb06b] font-cinzel font-black text-sm tracking-[0.2em] mb-1">
                      APPLICATION DEVELOPED BY KAZEHUNT
                  </div>
                  <div className="text-[#4a5f78] font-orbitron text-[9px] leading-relaxed tracking-[0.1em] uppercase max-w-2xl flex flex-col gap-2">
                      <p>DESIGNED EXCLUSIVELY FOR HONOR OF KINGS CUSTOM FUN MATCHES ON THE OFFICIAL DISCORD. THE DEVELOPER ASSUMES NO RESPONSIBILITY FOR USAGE OUTSIDE THIS INTENDED SCOPE.</p>
                  </div>
              </div>
          </footer>
        </>
      )}

      {currentMatch && viewMode !== 'lobby' && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={() => { setCurrentMatch(null); setViewMode('lobby'); }}
          onCompleteMatch={handleMatchFinish}
          onReroll={handleRerollSlot}
          onStartBattle={() => setViewMode('battle')}
        />
      )}
      <style>{`
        @keyframes chromatic {
          0% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
          25% { text-shadow: -2px 0 0 #ff0000, 2px 0 0 #0000ff; }
          50% { text-shadow: 2px -1px 0 #ff0000, -2px 1px 0 #0000ff; }
          75% { text-shadow: -2px 1px 0 #ff0000, 2px -1px 0 #0000ff; }
          100% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
        }
      `}</style>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {rating === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500">
           {rating === -2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  const gridClasses = isSidebarOpen ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => setFilter(val as FilterType)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-3 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';

          // High Priority: MVP/Coach Borders
          if (player.isActive) {
            if (isMvp) {
              glowColor = 'drop-shadow-[0_0_10px_#fbbf24]';
              animationLayer = <div className="absolute inset-[-100%] bg-[conic-gradient(from_0deg,transparent_0deg,#fbbf24_90deg,transparent_180deg,#fbbf24_270deg,transparent_360deg)] animate-[spin_4s_linear_infinite] opacity-100"></div>;
            } else if (isCoach) {
              glowColor = 'drop-shadow-[0_0_10px_white]';
              animationLayer = <div className="absolute inset-[-100%] bg-[conic-gradient(from_0deg,transparent_0deg,white_90deg,transparent_180deg,white_270deg,transparent_360deg)] animate-[spin_6s_linear_infinite] opacity-80"></div>;
            } else if (ws >= 2) {
              // Win Streak Hierarchy
              let wsColor = '#00d2ff'; // WS 2: Biru
              if (ws >= 5) wsColor = '#ef4444'; // WS 5: Merah
              else if (ws >= 4) wsColor = '#f97316'; // WS 4: Oren
              else if (ws >= 3) wsColor = '#a855f7'; // WS 3: Ungu

              glowColor = `drop-shadow-[0_0_8px_${wsColor}]`;
              animationLayer = <div style={{ background: `conic-gradient(from 0deg, transparent 0deg, ${wsColor} 120deg, transparent 180deg, ${wsColor} 300deg, transparent 360deg)` }} className="absolute inset-[-100%] animate-[spin_3s_linear_infinite] opacity-100"></div>;
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]">
                 {animationLayer}
              </div>
              <div className={`absolute inset-[1px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/50 grayscale'}`}>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase ${getRoleBadgeStyle(r)}`}>{r.split(' ')[0]}</span>)
                      )}
                    </div>
                  </div>
                  <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b]"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg></button>
                </div>

                {ws > 1 && player.isActive && (
                  <div className="absolute top-0 right-8 px-1.5 py-0.5 text-[7px] font-black uppercase tracking-wider bg-black/80 text-white border border-white/20 clip-corner-sm flex items-center gap-1">
                    <span className="animate-pulse">🔥</span> {ws} WS
                  </div>
                )}

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => onToggleActive(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => onEdit(players.find(p => p.id === menuOpenId)!)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => onRemove(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);

  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const formatRoleLabelShort = (role: Role) => {
    switch(role) {
        case Role.CLASH: return "CLASH";
        case Role.JUNGLE: return "JUNGLE";
        case Role.MID: return "MID";
        case Role.FARM: return "FARM";
        case Role.ROAM: return "ROAM";
        case Role.COACH: return "COACH";
        default: return (role as string).toUpperCase();
    }
  };

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    if (window.confirm("Are you sure you want to reveal all players and skip animations?")) {
        const allCards = new Set<string>();
        displayRoles.forEach(r => {
          allCards.add(getCardId('azure', r));
          allCards.add(getCardId('crimson', r));
        });
        setRevealedCards(allCards);
        setCurrentRoleIndex(displayRoles.length);
    }
  };

  const handleAbort = () => {
    if (window.confirm("Are you sure you want to abort the current draft? All progress will be lost.")) {
      onReset();
    }
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    match.azureTeam.forEach(slot => { if (revealedCards.has(getCardId('azure', slot.role))) revealedPlayerIds.add(slot.player.id); });
    match.crimsonTeam.forEach(slot => { if (revealedCards.has(getCardId('crimson', slot.role))) revealedPlayerIds.add(slot.player.id); });

    const candidates = activePlayers
      .filter(p => {
          if (revealedPlayerIds.has(p.id)) return false;
          if (role === Role.COACH) return p.roles.includes(Role.COACH);
          return p.isAllRoles || p.roles.includes(role);
      });

    const candidateNames = candidates.map(p => p.name);

    if (candidates.length === 1) {
        const cardId = getCardId(team, role);
        setAutoFillFlash(cardId);
        setRevealedCards(prev => new Set(prev).add(cardId));
        if (team === 'crimson') {
            setCurrentRoleIndex(prev => prev + 1);
        }
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    if (!candidateNames.includes(winner.name)) {
        candidateNames.push(winner.name);
    }

    const randomDuration = Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000;

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates: candidateNames,
      duration: randomDuration
    });
  };

  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return p.roles.includes(Role.COACH);
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    if (candidates.length === 1) {
        onReroll(team, role, candidates[0]);
        return;
    }

    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000; 

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const handleWheelCancel = () => setWheelState(null);
  const handleInitializeBattle = () => setViewState('transition');
  const handleTransitionComplete = () => { onStartBattle(); setViewState('final'); };
  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) { setWinningTeam(winner); setViewState('celebration'); } 
    else { onCompleteMatch(null); }
  };
  const handleCelebrationDismiss = () => setViewState('evaluation');
  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => { onCompleteMatch(winningTeam, mvpId, ratings); }

  if (viewState === 'evaluation' && winningTeam) return <EvaluationScreen match={match} winner={winningTeam} onComplete={handleEvaluationComplete} />;
  if (viewState === 'celebration' && winningTeam) return <VictoryCelebration winner={winningTeam} teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} onDismiss={handleCelebrationDismiss} />;
  if (viewState === 'transition') return <PortalTransition azureTeam={match.azureTeam} crimsonTeam={match.crimsonTeam} onComplete={handleTransitionComplete} />;
  if (viewState === 'final') return <MatchSummary match={match} onReset={handleMatchDecided} />;

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const cardId = getCardId(team, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.8)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : team === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-hok-cyan', glow: 'shadow-[0_0_10px_#00d2ff]', text: 'text-hok-cyan', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-hok-red', glow: 'shadow-[0_0_10px_#ef4444]', text: 'text-hok-red', gradient: 'from-[#c02d2d]/20 to-transparent' };

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-90 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${isAutoFilled ? 'shadow-[0_0_30px_#dcb06b] border-[#dcb06b]' : theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-1 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-0.5 px-2 py-0.5 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block scale-90 origin-${team === 'crimson' ? 'right' : 'left'}`}>
                {RoleIcons[role]}
             </div>
             <span className={`block text-lg md:text-xl font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>
             {isAutoFilled && (
                 <div className="absolute top-1 right-2 text-[8px] text-[#dcb06b] font-black uppercase tracking-tighter animate-pulse">Auto-Assigned</div>
             )}
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className={`absolute top-1 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20 ${team === 'azure' ? 'right-2' : 'left-2'}`}
             title="Re-roll this specific slot"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "START DRAFT";
  if (nextRoleName) {
     const nextTeam = !revealedCards.has(getCardId('azure', nextRoleName)) ? 'AZURE' : 'CRIMSON';
     const roleLabel = formatRoleLabelShort(nextRoleName);
     buttonText = `SELECT ${nextTeam} ${roleLabel}`;
  }

  return (
    <>
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates} 
          winnerName={wheelState.winnerName} 
          team={wheelState.team} 
          roleName={wheelState.role} 
          roomId={match.roomId} 
          duration={wheelState.duration}
          onComplete={handleWheelComplete} 
          onCancel={handleWheelCancel} 
        />
      )}
      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={handleAbort} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" /></svg> ABORT DRAFT</span>
           </Button>
           {!isFinished && <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">SKIP ALL</Button>}
        </div>

        {/* PRESTIGE NEON ROOM ID MATCH DISPLAY */}
        <div className="flex flex-col items-center mb-8 pt-8">
           <div className="flex flex-col items-center gap-1">
              <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase drop-shadow-sm mb-1">ROOM ID</span>
              <div className="relative">
                 <div className="absolute -inset-6 bg-[#dcb06b] blur-[30px] opacity-20 animate-pulse pointer-events-none"></div>
                 <div className="relative bg-black/80 border-2 border-[#dcb06b] px-16 py-4 clip-corner-sm flex flex-col items-center shadow-[0_0_40px_rgba(220,176,107,0.4)] transition-all">
                    <span className="text-4xl md:text-5xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_20px_#dcb06b] animate-[chromatic_0.2s_infinite]">
                      {match.roomId}
                    </span>
                 </div>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl mt-12">
              <div className="w-1/3 text-center"><h2 className="text-xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-200 to-cyan-600">AZURE GOLEM TEAM</h2></div>
              <div className="w-1/3 flex justify-center"><div className="relative w-20 h-20 flex items-center justify-center"><span className="text-3xl font-black italic text-[#dcb06b] z-10 animate-pulse-fast">VS</span></div></div>
              <div className="w-1/3 text-center"><h2 className="text-xl md:text-4xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-200 to-red-600">CRIMSON GOLEM TEAM</h2></div>
           </div>
        </div>

        <div className="relative space-y-2 md:space-y-3">
          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-8 items-center">
               <div className="order-1 md:order-none">{renderPlayerCard(role, idx, 'azure')}</div>
               <div className="order-2 md:order-none">{renderPlayerCard(role, idx, 'crimson')}</div>
            </div>
          ))}
        </div>
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end bg-gradient-to-t from-[#05090f] via-[#05090f]/90 to-transparent h-48 pointer-events-none">
           <div className="pointer-events-auto">
              {!isFinished ? (
                 <button onClick={handleNext} className="group relative px-12 h-16 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-lg hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_20px_rgba(220,176,107,0.2)]">
                   {buttonText}
                 </button>
              ) : (
                 <Button onClick={handleInitializeBattle} className="px-12 animate-pulse">INITIALIZE BATTLE</Button>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);

  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => {
        setIsLoading(false);
    }, 2500);

    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => {
            setElapsedSeconds(prev => prev + 1);
        }, 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); 
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     const type = e.dataTransfer.getData("type");
     if (type === "mvp-token") {
        setMvpId(playerId);
     }
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = 0;
          if (current <= 0) next = 1;
          else if (current === 1) next = 2;
          else next = 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = 0;
        if (current >= 0) next = -1;
        else if (current === -1) next = -2;
        else next = 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.2em] animate-pulse">CALCULATING BATTLE DATA</h2>
            <div className="w-64 h-1 bg-[#1e3a5f] mt-4 rounded overflow-hidden">
                <div className="h-full bg-[#dcb06b] animate-[loading-bar_2s_ease-in-out_infinite]"></div>
            </div>
        </div>
    );
  }

  const MVPToken = () => (
    <div 
      draggable 
      onDragStart={handleDragStart}
      className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"
    >
       <div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white animate-pulse">
           <span className="font-black italic text-[#05090f] text-xs">MVP</span>
       </div>
    </div>
  );

  const winningTeam = winner === 'azure' ? match.azureTeam : match.crimsonTeam;
  const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

  const renderTeamColumn = (teamSlots: typeof winningTeam, teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';

      return (
        <div className={`flex-1 w-full border ${borderColor} ${bgColor} p-0 clip-corner-md transition-all`}>
            <div className={`p-4 bg-opacity-30 border-b border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <div className="flex items-center gap-2">
                    <div className={`w-1 h-6 ${teamColor === 'cyan' ? 'bg-cyan-500' : 'bg-red-500'}`}></div>
                    <h3 className={`${textColor} font-cinzel font-bold text-xl`}>{teamName}</h3>
                </div>
                {isWinner && <span className="text-[#dcb06b] font-bold uppercase tracking-widest text-xs border border-[#dcb06b] px-2 py-1 rounded">Victory</span>}
            </div>

            <div className="p-4 space-y-2">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div 
                            key={role} 
                            onDragOver={!isCoach ? handleDragOver : undefined}
                            onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined}
                            className={`
                                flex items-center justify-between bg-[#0a1a2f]/50 p-3 rounded border relative overflow-hidden group transition-all
                                ${isMvp ? 'border-yellow-400 shadow-[0_0_15px_rgba(251,191,36,0.3)]' : isCoach ? 'border-white/20 bg-white/5' : 'border-white/5 hover:border-white/20'}
                            `}
                        >
                            <div className="flex items-center gap-4 relative z-10 flex-1 min-w-0">
                                <div className={`shrink-0 ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-500/50' : 'text-red-500/50')}`}>
                                    {RoleIcons[role]}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <div className={`text-lg font-orbitron truncate ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                            </div>
                            <div className="flex items-center gap-4 relative z-10 shrink-0">
                                {match.isCoachMode && (
                                    <div className="flex flex-col gap-1 mr-2 items-center">
                                        <button onClick={() => cycleRatingUp(slot.player.id)} className={`p-1 rounded hover:bg-white/10 ${rating > 0 ? 'text-green-400' : 'text-gray-600'}`}>
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
                                        </button>
                                        <button onClick={() => cycleRatingDown(slot.player.id)} className={`p-1 rounded hover:bg-white/10 ${rating < 0 ? 'text-red-500' : 'text-gray-600'}`}>
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
                                        </button>
                                    </div>
                                )}
                                {!isCoach && (
                                    <div className="w-10 h-10 flex items-center justify-center">
                                        {isMvp ? (
                                            <div className="w-8 h-8 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px]">MVP</div>
                                        ) : (
                                            <div className="w-8 h-8 border border-dashed border-white/10 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="relative z-10 w-full max-w-6xl animate-slide-in h-full overflow-y-auto py-8">
          <div className="text-center mb-6">
             <h1 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase mb-1">Evaluation</h1>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest uppercase mb-1">Session Duration</span>
                <div className="text-2xl font-mono font-bold text-white bg-black/50 px-6 py-1 rounded border border-[#dcb06b]/20">
                  {formatTime(elapsedSeconds)}
                </div>
             </div>
          </div>
          <div className="flex flex-col items-center mb-8">
             {!mvpId ? <MVPToken /> : <button onClick={() => setMvpId('')} className="text-xs text-red-400 underline uppercase tracking-widest">Reset MVP</button>}
          </div>
          <div className="flex flex-col md:flex-row gap-8 items-start justify-center">
             {renderTeamColumn(match.azureTeam, "AZURE GOLEM TEAM", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM TEAM", winner === 'crimson', 'red')}
          </div>
          <div className="mt-12 flex justify-center pb-8">
             <Button onClick={() => onComplete(mvpId, ratings)} className="px-16 py-4 text-xl shadow-[0_0_20px_#dcb06b]">FINISH EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {rating === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500">
           {rating === -2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  const gridClasses = isSidebarOpen ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => setFilter(val as FilterType)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-3 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';
          let primaryColor = '';

          // Logika Penentuan Warna dan Animasi Border Bergerak (Trace)
          if (player.isActive) {
            if (isMvp) {
              primaryColor = '#fbbf24'; // Emas
              glowColor = 'drop-shadow-[0_0_12px_#fbbf24]';
            } else if (isCoach) {
              primaryColor = '#ffffff'; // Putih
              glowColor = 'drop-shadow-[0_0_12px_rgba(255,255,255,0.6)]';
            } else if (ws >= 2) {
              if (ws >= 5) primaryColor = '#ef4444'; // Merah
              else if (ws >= 4) primaryColor = '#f97316'; // Oren
              else if (ws >= 3) primaryColor = '#a855f7'; // Ungu
              else primaryColor = '#00d2ff'; // Biru Cyan

              glowColor = `drop-shadow-[0_0_10px_${primaryColor}]`;
            }

            if (primaryColor) {
               // Membuat animasi garis "Trace" yang mengelilingi kartu
               animationLayer = (
                 <div 
                   className="absolute inset-[-150%] animate-[spin_4s_linear_infinite]"
                   style={{
                     background: `conic-gradient(from 0deg, ${primaryColor} 0deg, ${primaryColor} 40deg, transparent 40deg, transparent 180deg, ${primaryColor} 180deg, ${primaryColor} 220deg, transparent 220deg, transparent 360deg)`
                   }}
                 />
               );
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>
              {/* Container animasi border */}
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]/30">
                 {animationLayer}
              </div>

              {/* Inner Card (Masking area tengah agar hanya border 2px yang terlihat bergerak) */}
              <div className={`absolute inset-[2px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/50 grayscale'}`}>
                <div className="flex justify-between items-start mb-2">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase ${getRoleBadgeStyle(r)}`}>{r.split(' ')[0]}</span>)
                      )}
                    </div>
                  </div>
                  <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b]"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg></button>
                </div>

                {ws > 1 && player.isActive && (
                  <div className="absolute top-0 right-8 px-1.5 py-0.5 text-[7px] font-black uppercase tracking-wider bg-black/80 text-white border border-white/20 clip-corner-sm flex items-center gap-1">
                    <span className="animate-pulse">🔥</span> {ws} WS
                  </div>
                )}

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => onToggleActive(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => onEdit(players.find(p => p.id === menuOpenId)!)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => onRemove(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};

