                                            </div>
                                        </button>

                                        <button 
                                          onClick={() => cycleRatingDown(slot.player.id)} 
                                          className={`
                                            flex flex-col items-center justify-center w-10 h-12 rounded border transition-all duration-300
                                            ${rating < 0 
                                              ? 'bg-red-500/20 border-red-500 text-red-500 shadow-[0_0_10px_rgba(239,68,68,0.3)]' 
                                              : 'bg-black/40 border-white/10 text-gray-600 hover:border-red-500/50 hover:text-red-500/50'}
                                          `}
                                          title="Needs Improvement"
                                        >
                                            <div className="flex flex-col -space-y-2">
                                              {rating === -2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
                                              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
