import React, { useState, useEffect } from 'react';

export const WibClock: React.FC = () => {
  const [time, setTime] = useState(new Date());
  const [isMinimized, setIsMinimized] = useState(false);
  const [position, setPosition] = useState({ x: 20, y: 20 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formatWib = (date: Date) => {
    return new Intl.DateTimeFormat('id-ID', {
      timeZone: 'Asia/Jakarta',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: false
    }).format(date);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragOffset({
      x: e.clientX - position.x,
      y: e.clientY - position.y
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        setPosition({
          x: e.clientX - dragOffset.x,
          y: e.clientY - dragOffset.y
        });
      }
    };
    const handleMouseUp = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, dragOffset]);

  return (
    <div 
      className="fixed z-[900] select-none"
      style={{ left: position.x, top: position.y }}
    >
      <div 
        onMouseDown={handleMouseDown}
        className={`
          relative bg-[#0a1a2f]/90 border border-[#dcb06b]/40 backdrop-blur-md clip-corner-sm transition-all duration-300 group
          ${isMinimized ? 'w-12 h-12 flex items-center justify-center cursor-pointer' : 'p-3 w-40 cursor-move'}
        `}
      >
        <button 
          onClick={(e) => { e.stopPropagation(); setIsMinimized(!isMinimized); }}
          className="absolute -top-2 -right-2 w-5 h-5 bg-[#dcb06b] text-black rounded-full flex items-center justify-center text-[10px] font-black z-10 shadow-lg"
        >
          {isMinimized ? '+' : '-'}
        </button>

        {isMinimized ? (
          <div className="text-[#dcb06b]">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
        ) : (
          <div className="flex flex-col items-center">
            <span className="text-[#dcb06b] font-orbitron text-[8px] tracking-widest uppercase mb-1">Local Time (WIB)</span>
            <span className="text-white font-mono text-xl font-bold tracking-tighter drop-shadow-[0_0_8px_rgba(255,255,255,0.3)]">
              {formatWib(time)}
            </span>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);

  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => {
        setIsLoading(false);
    }, 2500);

    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => {
            setElapsedSeconds(prev => prev + 1);
        }, 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); 
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     const type = e.dataTransfer.getData("type");
     if (type === "mvp-token") {
        setMvpId(playerId);
     }
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = 0;
          if (current <= 0) next = 1;
          else if (current === 1) next = 2;
          else next = 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = 0;
        if (current >= 0) next = -1;
        else if (current === -1) next = -2;
        else next = 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 text-green-400 items-center justify-center animate-bounce">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 text-red-500 items-center justify-center animate-bounce">
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.2em] animate-pulse uppercase">Finalizing Combat Data</h2>
        </div>
    );
  }

  const winningTeam = winner === 'azure' ? match.azureTeam : match.crimsonTeam;
  const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

  const renderTeamColumn = (teamSlots: typeof winningTeam, teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';

      return (
        <div className={`flex-1 w-full border ${borderColor} ${bgColor} p-0 clip-corner-md transition-all`}>
            <div className={`p-4 bg-opacity-30 border-b border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <div className="flex items-center gap-2">
                    <h3 className={`${textColor} font-cinzel font-bold text-xl`}>{teamName}</h3>
                </div>
                {isWinner && <span className="text-[#dcb06b] font-bold uppercase tracking-widest text-xs border border-[#dcb06b] px-2 py-1 rounded">Victory</span>}
            </div>

            <div className="p-4 space-y-2">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div 
                            key={role} 
                            onDragOver={!isCoach ? handleDragOver : undefined}
                            onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined}
                            className={`
                                flex items-center justify-between bg-[#0a1a2f]/70 p-4 rounded border relative overflow-hidden group transition-all
                                ${isMvp ? 'border-yellow-400 shadow-[0_0_15px_rgba(251,191,36,0.2)]' : isCoach ? 'border-white/10' : 'border-white/5'}
                            `}
                        >
                            <div className="flex items-center gap-4 relative z-10 flex-1 min-w-0">
                                <div className={`shrink-0 ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-500/50' : 'text-red-500/50')}`}>
                                    {RoleIcons[role]}
                                </div>
                                <div className="flex items-center gap-2 min-w-0">
                                    <div className={`text-lg font-orbitron truncate ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                    {renderRatingArrows(rating)}
                                </div>
                            </div>

                            <div className="flex items-center gap-2 relative z-10 shrink-0">
                                {match.isCoachMode && (
                                    <div className="flex items-center gap-1 bg-black/40 p-1 rounded border border-white/5">
                                        <button onClick={() => cycleRatingUp(slot.player.id)} className={`w-8 h-8 flex items-center justify-center rounded hover:bg-white/10 ${rating > 0 ? 'text-green-400' : 'text-gray-600'}`}>
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                                        </button>
                                        <button onClick={() => cycleRatingDown(slot.player.id)} className={`w-8 h-8 flex items-center justify-center rounded hover:bg-white/10 ${rating < 0 ? 'text-red-500' : 'text-gray-600'}`}>
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M20 12H4" /></svg>
                                        </button>
                                    </div>
                                )}
                                {!isCoach && (
                                    <div className="w-10 h-10 flex items-center justify-center">
                                        {isMvp ? (
                                            <div className="w-8 h-8 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px] shadow-[0_0_10px_gold]">MVP</div>
                                        ) : (
                                            <div className="w-8 h-8 border border-dashed border-white/10 rounded-full opacity-10 group-hover:opacity-100 transition-all"></div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="relative z-10 w-full max-w-6xl animate-slide-in h-full overflow-y-auto py-8">
          <div className="text-center mb-6">
             <h1 className="text-4xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase mb-1">Combat Evaluation</h1>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest uppercase mb-1">Mission Duration</span>
                <div className="text-2xl font-mono font-bold text-white bg-black/60 px-8 py-2 rounded border border-[#dcb06b]/20">
                  {formatTime(elapsedSeconds)}
                </div>
             </div>
          </div>
          <div className="flex flex-col items-center mb-8">
             {!mvpId ? (
                <div 
                   draggable 
                   onDragStart={(e) => { e.dataTransfer.setData("type", "mvp-token"); e.dataTransfer.effectAllowed = "move"; }}
                   className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"
                >
                   <div className="w-16 h-16 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_20px_gold] border-2 border-white animate-pulse">
                       <span className="font-black italic text-black text-sm">MVP</span>
                   </div>
                   <p className="text-[10px] text-[#dcb06b] mt-2 uppercase tracking-widest text-center opacity-60">Seret Ke Pemain</p>
                </div>
             ) : <button onClick={() => setMvpId('')} className="px-4 py-2 border border-red-500/30 text-red-500 text-[10px] uppercase font-bold hover:bg-red-500 hover:text-white transition-all">Reset MVP</button>}
          </div>
          <div className="flex flex-col md:flex-row gap-6 items-start justify-center">
             {renderTeamColumn(match.azureTeam, "AZURE GOLEM", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM", winner === 'crimson', 'red')}
          </div>
          <div className="mt-12 flex justify-center pb-12">
             <Button onClick={() => onComplete(mvpId, ratings)} className="px-16 py-4 text-xl">FINALIZE EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry } from './types';
import { PlayerForm } from './components/PlayerForm';
