  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

type ViewMode = 'lobby' | 'match' | 'battle';
export type Lang = 'ID' | 'EN';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');
  const [lang, setLang] = useState<Lang>('ID');
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [matchCount, setMatchCount] = useState(1);
  const [showWelcome, setShowWelcome] = useState(true);

  const t = {
    ID: {
      presence: "Kehadiran Squad",
      roster: "Daftar Tempur",
      history: "Arsip Pertempuran",
      generate: "MULAILAH DRAFT",
      quickFill: "Isi Cepat",
      roomAccess: "AKSES ROOM ID",
      wipe: "Hapus Data",
      coachActive: "STRATEGI COACH: AKTIF",
      coachInactive: "STRATEGI COACH: NONAKTIF",
      errorRoom: "Tentukan Room ID!",
      errorPlayers: (req: number) => `Butuh minimal ${req} pemain AKTIF.`,
      footer: "PROJECT DIKEMBANGKAN UNTUK KEPERLUAN CUSTOM MATCH HONOR OF KINGS DISCORD INDONESIA."
    },
    EN: {
      presence: "Squad Presence",
      roster: "Combatant Roster",
      history: "Battle Archives",
      generate: "START BATTLE DRAFT",
      quickFill: "Quick Fill",
      roomAccess: "ROOM ID ACCESS",
      wipe: "Wipe Data",
      coachActive: "COACH STRATEGY: ACTIVE",
      coachInactive: "COACH STRATEGY: INACTIVE",
      errorRoom: "Assign Room ID!",
      errorPlayers: (req: number) => `Need at least ${req} ACTIVE players.`,
      footer: "PROJECT DEVELOPED FOR HONOR OF KINGS DISCORD INDONESIA CUSTOM MATCHES."
    }
  }[lang];

  const navigate = useCallback((mode: ViewMode, data: any) => {
    setViewMode(mode);
    if (mode === 'lobby' && Array.isArray(data)) setPlayers(data);
    else if ((mode === 'match' || mode === 'battle') && data) setCurrentMatch(data);
  }, []);

  const handleBatchProcess = (batchData: any[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], roles: item.roles, isAllRoles: item.isAllRoles, isActive: true };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };
  const handleUpdatePlayer = (updatedPlayer: Player) => setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) { setErrorMsg(t.errorRoom); return; }
    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) { setErrorMsg(t.errorPlayers(required)); return; }
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) { setCurrentMatch(result); setErrorMsg(null); navigate('match', result); }
    else { setErrorMsg(lang === 'ID' ? "Komposisi tim gagal." : "Failed to find composition."); }
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);
    const updatedPlayers = players.map(p => {
      const isMvp = mvpId === p.id;
      const matchPlayer = [...currentMatch.azureTeam, ...currentMatch.crimsonTeam].find(s => s.player.id === p.id);
      if (!matchPlayer) return { ...p, isLastMatchMvp: false };
      const isAzure = currentMatch.azureTeam.some(s => s.player.id === p.id);
      const isWinner = winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson'));
      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };
      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }
      return { ...p, stats: newStats, isLastMatchMvp: isMvp, lastMatchRating: ratings?.[p.id] || 0 };
    });
    setPlayers(updatedPlayers); setMatchCount(prev => prev + 1); setShowWelcome(true); navigate('lobby', updatedPlayers); setCurrentMatch(null); setRoomId('');
  };

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const batchData = shuffledHeroes.slice(0, 15).map(hero => ({ name: hero.name, roles: hero.roles, isAllRoles: false, action: 'add' as const }));
     for(let i=0; i<5; i++) batchData.push({ name: `Player ${i+1}`, roles: [], isAllRoles: true, action: 'add' });
     if (isCoachMode) {
        batchData.push({ name: "Coach HoK", roles: [Role.COACH], isAllRoles: false, action: 'add' });
        batchData.push({ name: "Coach Global", roles: [Role.COACH], isAllRoles: false, action: 'add' });
     }
     handleBatchProcess(batchData);
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <WibClock />
      <WelcomeModal isOpen={showWelcome} onClose={() => setShowWelcome(false)} matchNumber={matchCount} lastWinner={matchHistory[0]?.winningTeam || null} lang={lang} />

      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/95 via-[#05090f]/70 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />}

      {viewMode === 'lobby' && (
        <>
          <nav className="relative z-50 flex justify-end p-4 max-w-7xl mx-auto w-full">
            <div className="flex bg-[#0a1a2f]/80 border border-[#dcb06b]/30 p-1 clip-corner-sm">
               <button onClick={() => setLang('ID')} className={`px-4 py-1 text-xs font-bold transition-all ${lang === 'ID' ? 'bg-[#dcb06b] text-black' : 'text-[#8a9db8] hover:text-[#dcb06b]'}`}>ID</button>
               <div className="w-[1px] bg-[#dcb06b]/20"></div>
               <button onClick={() => setLang('EN')} className={`px-4 py-1 text-xs font-bold transition-all ${lang === 'EN' ? 'bg-[#dcb06b] text-black' : 'text-[#8a9db8] hover:text-[#dcb06b]'}`}>EN</button>
            </div>
          </nav>

          <main className="relative z-10 pt-4 px-4 flex-grow max-w-7xl mx-auto w-full">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
              <div className={`lg:col-span-4 space-y-4 ${isSidebarOpen ? '' : 'hidden'}`}>
                <div className="relative group">
                  <div className="absolute -inset-[1px] bg-[#dcb06b]/50 clip-corner-md opacity-30"></div>
                  <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative flex flex-col items-center">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-3">{t.roomAccess}</span>
                    <div className="relative w-full">
                      <div className="relative bg-black/60 border border-[#dcb06b]/30 py-4 px-4 clip-corner-sm flex flex-col items-center">
                         <input type="text" value={roomId} onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} placeholder="0000" className={`bg-transparent text-5xl font-orbitron font-black w-full text-center focus:outline-none tracking-[0.4em] transition-all duration-300 ${roomId ? 'text-white drop-shadow-[0_0_15px_#dcb06b] animate-[chromatic_0.2s_infinite]' : 'text-[#1e3a5f]'}`}/>
                      </div>
                    </div>
                  </div>
                </div>

                <button onClick={() => setIsCoachMode(!isCoachMode)} className="relative w-full group overflow-hidden p-[1px] clip-corner-sm">
                   <div className={`relative z-10 py-4 px-6 flex items-center justify-center transition-all duration-300 clip-corner-sm border ${isCoachMode ? 'bg-[#dcb06b]/10 border-[#dcb06b] text-[#dcb06b]' : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}`}>
                      <span className={`font-cinzel font-black text-xs tracking-[0.2em] uppercase ${isCoachMode ? 'text-white drop-shadow-[0_0_8px_#dcb06b]' : ''}`}>{isCoachMode ? t.coachActive : t.coachInactive}</span>
                   </div>
                </button>

                <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} lang={lang} />
                <div className="relative p-6 clip-corner-md bg-[#0a1a2f]/80 backdrop-blur-md border border-[#1e3a5f]">
                   <div className="flex justify-between items-end mb-6">
                      <div className="flex flex-col">
                         <span className="text-[#8a9db8] text-[9px] uppercase font-bold tracking-widest mb-1">{t.presence}</span>
                         <div className="flex items-baseline gap-2">
                            <span className="text-4xl font-orbitron font-bold text-white">{activePlayers.length}</span>
                            <span className="text-sm font-orbitron text-[#4a5f78]">/ {players.length}</span>
                         </div>
                      </div>
                      <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b]/30 px-3 py-1.5 hover:bg-[#dcb06b] hover:text-black transition-all clip-corner-sm uppercase font-bold">{t.quickFill}</button>
                   </div>
                   {errorMsg && <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/40 text-red-200 text-[10px] font-bold uppercase">{errorMsg}</div>}
                   <Button onClick={handleGenerate} className="w-full">{t.generate}</Button>
                </div>
              </div>

              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex items-center justify-between mb-4 bg-black/40 p-4 border border-[#1e3a5f] clip-corner-sm">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 border border-[#1e3a5f] text-[#dcb06b] hover:border-[#dcb06b] transition-all">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
                    </button>
                    <h2 className="text-xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase">{t.roster}</h2>
                    <button onClick={() => { if(window.confirm(lang === 'ID' ? "Hapus semua?" : "Clear all?")) setPlayers([]); }} className="text-[10px] text-[#4a5f78] hover:text-red-400 uppercase font-bold tracking-tighter transition-colors">{t.wipe}</button>
                 </div>
                 <div className="p-6 bg-[#05090f]/90 clip-corner-md min-h-[500px]">
                    <PlayerList players={players} onRemove={removePlayer} onToggleActive={togglePlayerActive} onEdit={handleEditPlayer} isSidebarOpen={isSidebarOpen} lang={lang} />
                 </div>
                 <div className="mt-8 p-6 bg-black/40 border border-[#1e3a5f] clip-corner-sm">
                    <h2 className="text-xl font-cinzel font-black text-[#dcb06b] mb-6 tracking-widest uppercase">{t.history}</h2>
                    <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} lang={lang} />
                 </div>
              </div>
            </div>
          </main>

          <footer className="py-12 px-6 text-center border-t border-[#dcb06b]/5 bg-black/80 mt-12">
              <div className="max-w-4xl mx-auto flex flex-col items-center gap-3">
                  <div className="text-[#dcb06b] font-cinzel font-black text-[10px] tracking-[0.4em] mb-1 uppercase leading-loose">
                      EST. 2025 // APP DEVELOPED BY KAZEHUNT
                  </div>
                  <div className="text-[#1e3a5f] font-orbitron text-[8px] leading-relaxed tracking-[0.2em] uppercase max-w-2xl">
                      {t.footer}
                  </div>
              </div>
          </footer>
        </>
      )}

      {currentMatch && viewMode !== 'lobby' && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={() => { setCurrentMatch(null); setViewMode('lobby'); }}
          onCompleteMatch={handleMatchFinish}
          onReroll={(team, role, p) => {
             if (!currentMatch) return;
             const updated = {
                ...currentMatch,
                azureTeam: currentMatch.azureTeam.map(s => (team === 'azure' && s.role === role) ? { ...s, player: p } : s),
                crimsonTeam: currentMatch.crimsonTeam.map(s => (team === 'crimson' && s.role === role) ? { ...s, player: p } : s)
             };
             setCurrentMatch(updated);
          }}
          onStartBattle={() => setViewMode('battle')}
          lang={lang}
        />
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';

export const WibClock: React.FC = () => {
  const [time, setTime] = useState(new Date());
  const [isMinimized, setIsMinimized] = useState(false);
  // Default position: bottom right
  const [position, setPosition] = useState({ 
    x: window.innerWidth - 180, 
    y: window.innerHeight - 100 
  });
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formatWib = (date: Date) => {
    return new Intl.DateTimeFormat('id-ID', {
      timeZone: 'Asia/Jakarta',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: false
    }).format(date);
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setDragOffset({
      x: e.clientX - position.x,
      y: e.clientY - position.y
    });
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        setPosition({
          x: e.clientX - dragOffset.x,
          y: e.clientY - dragOffset.y
        });
      }
    };
    const handleMouseUp = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, dragOffset]);

  return (
    <div 
      className="fixed z-[900] select-none"
      style={{ left: position.x, top: position.y }}
    >
      <div 
        onMouseDown={handleMouseDown}
        className={`
          relative bg-[#0a1a2f]/90 border border-[#dcb06b]/40 backdrop-blur-md clip-corner-sm transition-all duration-300 group
          ${isMinimized ? 'w-12 h-12 flex items-center justify-center cursor-pointer' : 'p-3 w-40 cursor-move'}
        `}
      >
        <button 
          onClick={(e) => { e.stopPropagation(); setIsMinimized(!isMinimized); }}
          className="absolute -top-2 -right-2 w-5 h-5 bg-[#dcb06b] text-black rounded-full flex items-center justify-center text-[10px] font-black z-10 shadow-lg"
        >
          {isMinimized ? '+' : '-'}
        </button>

        {isMinimized ? (
          <div className="text-[#dcb06b]">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
        ) : (
          <div className="flex flex-col items-center">
            <span className="text-[#dcb06b] font-orbitron text-[8px] tracking-widest uppercase mb-1">Local Time (WIB)</span>
            <span className="text-white font-mono text-xl font-bold tracking-tighter drop-shadow-[0_0_8px_rgba(255,255,255,0.3)]">
              {formatWib(time)}
            </span>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);

  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => {
        setIsLoading(false);
    }, 2500);

    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => {
            setElapsedSeconds(prev => prev + 1);
        }, 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); 
    e.dataTransfer.dropEffect = "move";
  };

  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     const type = e.dataTransfer.getData("type");
     if (type === "mvp-token") {
        setMvpId(playerId);
     }
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = 0;
          if (current <= 0) next = 1;
          else if (current === 1) next = 2;
          else next = 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = 0;
        if (current >= 0) next = -1;
        else if (current === -1) next = -2;
        else next = 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 text-green-400 items-center justify-center animate-bounce">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 text-red-500 items-center justify-center animate-bounce">
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.2em] animate-pulse uppercase">Finalizing Combat Data</h2>
        </div>
    );
  }

  const winningTeam = winner === 'azure' ? match.azureTeam : match.crimsonTeam;
  const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

  const renderTeamColumn = (teamSlots: typeof winningTeam, teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const borderColor = teamColor === 'cyan' ? 'border-[#00d2ff]' : 'border-[#ef4444]';
      const bgColor = teamColor === 'cyan' ? 'bg-[#00d2ff]/10' : 'bg-[#ef4444]/10';
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';

      return (
        <div className={`flex-1 w-full border ${borderColor} ${bgColor} p-0 clip-corner-md transition-all`}>
            <div className={`p-4 bg-opacity-30 border-b border-white/10 flex justify-between items-center ${teamColor === 'cyan' ? 'bg-[#00d2ff]' : 'bg-[#ef4444]'}`}>
                <div className="flex items-center gap-2">
                    <h3 className={`${textColor} font-cinzel font-bold text-xl`}>{teamName}</h3>
                </div>
                {isWinner && <span className="text-[#dcb06b] font-bold uppercase tracking-widest text-xs border border-[#dcb06b] px-2 py-1 rounded">Victory</span>}
            </div>

            <div className="p-4 space-y-2">
                {rolesToRender.map(role => {
                    const slot = teamSlots.find(s => s.role === role);
                    if(!slot) return null;
                    const isMvp = slot.player.id === mvpId;
                    const rating = ratings[slot.player.id] || 0;
                    const isCoach = role === Role.COACH;

                    return (
                        <div 
                            key={role} 
                            onDragOver={!isCoach ? handleDragOver : undefined}
                            onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined}
                            className={`
                                flex items-center justify-between bg-[#0a1a2f]/70 p-4 rounded border relative overflow-hidden group transition-all
                                ${isMvp ? 'border-yellow-400 shadow-[0_0_15px_rgba(251,191,36,0.2)]' : isCoach ? 'border-white/10' : 'border-white/5'}
                            `}
                        >
                            <div className="flex items-center gap-4 relative z-10 flex-1 min-w-0">
                                <div className={`shrink-0 ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-500/50' : 'text-red-500/50')}`}>
                                    {RoleIcons[role]}
                                </div>
                                <div className="flex items-center gap-2 min-w-0">
                                    <div className={`text-lg font-orbitron truncate ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                    {!isCoach && renderRatingArrows(rating)}
                                </div>
                            </div>

                            <div className="flex items-center gap-2 relative z-10 shrink-0">
                                {!isCoach && (
                                    <div className="flex items-center gap-1 bg-black/40 p-1 rounded border border-white/5">
                                        <button onClick={() => cycleRatingUp(slot.player.id)} className={`w-8 h-8 flex items-center justify-center rounded hover:bg-white/10 ${rating > 0 ? 'text-green-400' : 'text-gray-600'}`}>
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
                                        </button>
                                        <button onClick={() => cycleRatingDown(slot.player.id)} className={`w-8 h-8 flex items-center justify-center rounded hover:bg-white/10 ${rating < 0 ? 'text-red-500' : 'text-gray-600'}`}>
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M20 12H4" /></svg>
                                        </button>
                                    </div>
                                )}
                                {!isCoach && (
                                    <div className="w-10 h-10 flex items-center justify-center">
                                        {isMvp ? (
                                            <div className="w-8 h-8 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px] shadow-[0_0_10px_gold]">MVP</div>
                                        ) : (
                                            <div className="w-8 h-8 border border-dashed border-white/10 rounded-full opacity-10 group-hover:opacity-100 transition-all"></div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="relative z-10 w-full max-w-6xl animate-slide-in h-full overflow-y-auto py-8">
          <div className="text-center mb-6">
             <h1 className="text-4xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase mb-1">Combat Evaluation</h1>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest uppercase mb-1">Mission Duration</span>
                <div className="text-2xl font-mono font-bold text-white bg-black/60 px-8 py-2 rounded border border-[#dcb06b]/20">
                  {formatTime(elapsedSeconds)}
                </div>
             </div>
          </div>
          <div className="flex flex-col items-center mb-8">
             {!mvpId ? (
                <div 
                   draggable 
                   onDragStart={(e) => { e.dataTransfer.setData("type", "mvp-token"); e.dataTransfer.effectAllowed = "move"; }}
                   className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"
                >
                   <div className="w-16 h-16 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_20px_gold] border-2 border-white animate-pulse">
                       <span className="font-black italic text-black text-sm">MVP</span>
                   </div>
                   <p className="text-[10px] text-[#dcb06b] mt-2 uppercase tracking-widest text-center opacity-60">Seret Ke Pemain</p>
                </div>
             ) : <button onClick={() => setMvpId('')} className="px-4 py-2 border border-red-500/30 text-red-500 text-[10px] uppercase font-bold hover:bg-red-500 hover:text-white transition-all">Reset MVP</button>}
          </div>
          <div className="flex flex-col md:flex-row gap-6 items-start justify-center">
             {renderTeamColumn(match.azureTeam, "AZURE GOLEM", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM", winner === 'crimson', 'red')}
          </div>
          <div className="mt-12 flex justify-center pb-12">
             <Button onClick={() => onComplete(mvpId, ratings)} className="px-16 py-4 text-xl">FINALIZE EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

/**
 * Shared language type for localization.
