import React, { useState } from 'react';
import { Player, Role, Lang } from '../types';
import { Button } from './Button';
import { ROLES_ORDER } from '../constants';

interface BatchItem {
  name: string;
  roles: Role[];
  isAllRoles: boolean;
  action: 'add' | 'bench';
}

interface PlayerFormProps {
  onBatchProcess: (items: BatchItem[]) => void;
  isCoachMode: boolean;
  lang?: Lang;
}

export const PlayerForm: React.FC<PlayerFormProps> = ({ onBatchProcess, isCoachMode }) => {
  const [mode, setMode] = useState<'manual' | 'smart'>('manual');
  const [name, setName] = useState('');
  const [isAllRoles, setIsAllRoles] = useState(false);
  const [selectedRoles, setSelectedRoles] = useState<Role[]>([]);
  const [smartInput, setSmartInput] = useState('');

  const toggleRole = (role: Role) => {
    if (isAllRoles) return;
    if (role === Role.COACH) {
        setSelectedRoles(prev => prev.includes(Role.COACH) ? [] : [Role.COACH]);
        return;
    }
    let currentRoles = selectedRoles.filter(r => r !== Role.COACH);
    currentRoles = currentRoles.includes(role) ? currentRoles.filter(r => r !== role) : [...currentRoles, role];
    if (ROLES_ORDER.every(r => currentRoles.includes(r))) { setIsAllRoles(true); setSelectedRoles([]); }
    else { setSelectedRoles(currentRoles); }
  };

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim() || (!isAllRoles && selectedRoles.length === 0)) return;
    onBatchProcess([{ name: name.trim(), isAllRoles, roles: isAllRoles ? [] : selectedRoles, action: 'add' }]);
    setName(''); setIsAllRoles(false); setSelectedRoles([]);
  };

  const parseAndSubmitSmartInput = (e: React.FormEvent) => {
    e.preventDefault();
    if (!smartInput.trim()) return;
    const lines = smartInput.split(/\n/);
    const batchItems: BatchItem[] = [];
    lines.forEach(line => {
      const cleanLine = line.trim();
      if (!cleanLine) return;

      // Supported separators: colon, dash, or just a space
      const parts = cleanLine.split(/[:|-]/);
      if (parts.length < 1) return;

      const pName = parts[0].trim();
      // If no separator, look for role keywords in the whole line
      const pRoleStr = (parts.length > 1 ? parts[1] : cleanLine).toLowerCase();

      let pIsAllRoles = false;
      const pRoles: Role[] = [];
      let pAction: 'add' | 'bench' = 'add';

      if (pRoleStr.includes('stop') || pRoleStr.includes('bench') || pRoleStr.includes('out') || pRoleStr.includes('afk') || pRoleStr.includes('off')) {
         pAction = 'bench';
      } else {
         if (pRoleStr.includes('all') || pRoleStr.includes('fill') || pRoleStr.includes('any') || pRoleStr.includes('auto')) {
            pIsAllRoles = true;
         } else {
            if (pRoleStr.includes('clash') || pRoleStr.includes('exp') || pRoleStr.includes('fight') || pRoleStr.includes('clsh')) pRoles.push(Role.CLASH);
            if (pRoleStr.includes('mid') || pRoleStr.includes('mage') || pRoleStr.includes('central')) pRoles.push(Role.MID);
            if (pRoleStr.includes('jung') || pRoleStr.includes('jg') || pRoleStr.includes('assassin') || pRoleStr.includes('hunt')) pRoles.push(Role.JUNGLE);
            if (pRoleStr.includes('farm') || pRoleStr.includes('gold') || pRoleStr.includes('mm') || pRoleStr.includes('adc') || pRoleStr.includes('archer') || pRoleStr.includes('marksman')) pRoles.push(Role.FARM);
            if (pRoleStr.includes('roam') || pRoleStr.includes('supp') || pRoleStr.includes('tank') || pRoleStr.includes('helper')) pRoles.push(Role.ROAM);
            if (isCoachMode && (pRoleStr.includes('coach') || pRoleStr.includes('trainer') || pRoleStr.includes('mgr'))) pRoles.push(Role.COACH);
         }
      }

      if (pName && (pAction === 'bench' || pIsAllRoles || pRoles.length > 0)) {
        batchItems.push({ name: pName, isAllRoles: pIsAllRoles, roles: pRoles, action: pAction });
      }
    });
    if (batchItems.length > 0) { onBatchProcess(batchItems); setSmartInput(''); }
  };

  const smartPlaceholder = `--- UPDATE / ADD NEW PLAYERS ---
IGN : Mid Lane
P2 - Jungle
P3 (All Roles)
P4: Farm, Roam
CoachElite : Coach

--- BENCH / DEACTIVATE PLAYERS ---
IGN: stop
P2 - bench
P3: out
P4 - afk
P5 (off)
P6: benched`;

  return (
    <div className="relative group">
      <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-50"></div>
      <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative">
        <div className="flex items-center justify-between mb-6 border-b border-[#dcb06b]/20 pb-4">
          <h3 className="text-xl text-[#dcb06b] font-cinzel font-bold tracking-widest">{mode === 'manual' ? 'New Challenger' : 'Smart Import'}</h3>
          <div className="flex bg-[#05090f] p-1 rounded clip-corner-sm border border-[#1e3a5f]">
             <button onClick={() => setMode('manual')} className={`px-3 py-1 text-[10px] uppercase font-bold transition-all ${mode === 'manual' ? 'bg-[#dcb06b] text-[#05090f]' : 'text-[#4a5f78] hover:text-[#dcb06b]'}`}>Manual</button>
             <button onClick={() => setMode('smart')} className={`px-3 py-1 text-[10px] uppercase font-bold transition-all ${mode === 'smart' ? 'bg-[#dcb06b] text-[#05090f]' : 'text-[#4a5f78] hover:text-[#dcb06b]'}`}>Smart Paste</button>
          </div>
        </div>

        {mode === 'manual' ? (
          <form onSubmit={handleManualSubmit}>
            <div className="mb-6">
              <label className="block text-[10px] uppercase tracking-widest text-[#8a9db8] mb-2 font-bold">Player Name</label>
              <input type="text" value={name} onChange={e => setName(e.target.value)} placeholder="ENTER IGN..." className="w-full bg-[#05090f] border border-[#1e3a5f] p-4 text-[#f0f4f8] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
            </div>
            <div className="mb-8">
              <div className="flex justify-between items-end mb-4">
                 <label className="text-[10px] uppercase tracking-widest text-[#8a9db8] font-bold">Role Preference</label>
                 <label className="flex items-center cursor-pointer">
                  <span className={`mr-3 text-xs font-bold font-orbitron transition-colors ${isAllRoles ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>All Roles</span>
                  <input type="checkbox" className="hidden" checked={isAllRoles} onChange={e => setIsAllRoles(e.target.checked)}/>
                  <div className={`w-10 h-5 rounded-full relative transition-colors ${isAllRoles ? 'bg-[#dcb06b]' : 'bg-[#1e3a5f]'}`}>
                     <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-transform ${isAllRoles ? 'left-6' : 'left-1'}`}></div>
                  </div>
                </label>
              </div>
              <div className={`flex flex-wrap gap-2 ${isAllRoles ? 'opacity-30 pointer-events-none' : ''}`}>
                {(isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER).map(role => (
                  <button key={role} type="button" onClick={() => toggleRole(role)} className={`px-4 py-2 font-cinzel font-bold text-[10px] uppercase tracking-widest clip-corner-sm border transition-all ${selectedRoles.includes(role) ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b] hover:text-[#dcb06b]'}`}>
                    {role.replace(' Lane', '')}
                  </button>
                ))}
              </div>
            </div>
            <Button type="submit" className="w-full" disabled={!name || (!isAllRoles && selectedRoles.length === 0)}>Join Lobby</Button>
          </form>
        ) : (
          <form onSubmit={parseAndSubmitSmartInput}>
            <div className="mb-4">
              <label className="block text-[10px] uppercase tracking-widest text-[#8a9db8] mb-2 font-bold">Paste Roster List</label>
              <textarea value={smartInput} onChange={e => setSmartInput(e.target.value)} placeholder={smartPlaceholder} className="w-full h-56 bg-[#05090f] border border-[#1e3a5f] p-4 text-[#f0f4f8] placeholder-[#2d4a6d] focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron text-[10px] leading-relaxed resize-none"/>
            </div>
            <Button type="submit" className="w-full" disabled={!smartInput.trim()}>Process Batch</Button>
          </form>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role, Lang } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
  lang?: Lang;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;

    // Pastikan panah dirender dua kali jika nilai mutlaknya adalah 2
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400 items-center justify-center">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500 items-center justify-center">
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  const gridClasses = isSidebarOpen ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => setFilter(val as FilterType)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-3 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';
          let primaryColor = '';

          // Hirarki Status & Warna Trace Border
          if (player.isActive) {
            if (isMvp) {
              primaryColor = '#fbbf24'; // Emas
              glowColor = 'drop-shadow-[0_0_12px_#fbbf24]';
            } else if (isCoach) {
              primaryColor = '#ffffff'; // Putih
              glowColor = 'drop-shadow-[0_0_12px_rgba(255,255,255,0.6)]';
            } else if (ws >= 2) {
              if (ws >= 5) primaryColor = '#ef4444'; // Merah
              else if (ws >= 4) primaryColor = '#f97316'; // Oren
              else if (ws >= 3) primaryColor = '#a855f7'; // Ungu
              else primaryColor = '#00d2ff'; // Biru Cyan

              glowColor = `drop-shadow-[0_0_10px_${primaryColor}]`;
            }

            if (primaryColor) {
               animationLayer = (
                 <div 
                   className="absolute inset-[-150%] animate-[spin_4s_linear_infinite]"
                   style={{
                     background: `conic-gradient(from 0deg, ${primaryColor} 0deg, ${primaryColor} 40deg, transparent 40deg, transparent 180deg, ${primaryColor} 180deg, ${primaryColor} 220deg, transparent 220deg, transparent 360deg)`
                   }}
                 />
               );
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>
              {/* Animated Border Background */}
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]/20">
                 {animationLayer}
              </div>

              {/* Inner Card content */}
              <div className={`absolute inset-[2px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/80 grayscale backdrop-blur-sm'}`}>

                {/* BENCHED STAMP - Only for inactive players */}
                {!player.isActive && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center pointer-events-none overflow-hidden">
                        <div className="absolute inset-0 bg-red-900/10 mix-blend-overlay"></div>
                        <div className="rotate-[-15deg] border-4 border-red-600/80 px-4 py-1 text-red-600/90 font-black text-2xl tracking-[0.3em] uppercase bg-black/40 backdrop-blur-sm shadow-[0_0_20px_rgba(220,38,38,0.4)] animate-pulse-fast">
                            BENCHED
                        </div>
                    </div>
                )}

                <div className="flex justify-between items-start mb-2 relative z-10">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase ${getRoleBadgeStyle(r)}`}>{r.split(' ')[0]}</span>)
                      )}
                    </div>
                  </div>

                  {/* Status Mini-Tags */}
                  <div className="flex flex-col items-end gap-1">
                    <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b] mb-1">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg>
                    </button>

                    <div className="flex flex-col gap-1 items-end">
                       {/* MVP Mini-Tag */}
                       {isMvp && player.isActive && (
                         <div className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter bg-[#fbbf24] text-black clip-corner-sm shadow-[0_0_8px_rgba(251,191,36,0.6)]">
                            MVP
                         </div>
                       )}

                       {/* Win Streak Mini-Tag */}
                       {ws >= 2 && player.isActive && (
                         <div 
                           className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter text-white clip-corner-sm shadow-md"
                           style={{ backgroundColor: primaryColor }}
                         >
                            {ws} WS
                         </div>
                       )}
                    </div>
                  </div>
                </div>

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1 relative z-10">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => onToggleActive(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => onEdit(players.find(p => p.id === menuOpenId)!)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => onRemove(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};

import React, { useState } from 'react';
import { MatchHistoryEntry, Role, Lang } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';

interface HistoryListProps {
  history: MatchHistoryEntry[];
  onClear: () => void;
  lang?: Lang;
}

export const HistoryList: React.FC<HistoryListProps> = ({ history, onClear }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);

  if (history.length === 0) {
    return (
      <div className="p-8 text-center border border-[#1e3a5f] bg-[#0a1a2f]/40 rounded">
        <p className="text-[#8a9db8] font-cinzel tracking-widest text-sm">No match history recorded yet.</p>
      </div>
    );
  }

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  const formatDate = (ts: number) => {
    return new Date(ts).toLocaleString();
  };

  const renderRatingArrow = (rating: number) => {
      if (!rating || rating === 0) return null;

      if (rating > 0) {
          // Positive
          return (
             <div className="flex flex-col -space-y-1 text-green-400 ml-2" title="Performance: Good">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
                 {rating === 2 && (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
                 )}
             </div>
          );
      } else {
          // Negative
          return (
             <div className="flex flex-col -space-y-1 text-red-500 ml-2" title="Performance: Bad">
                 {rating === -2 && (
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
                 )}
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
             </div>
          );
      }
  };

  return (
    <div className="space-y-4">
       <div className="flex justify-between items-center mb-4">
          <h3 className="text-[#dcb06b] font-cinzel text-lg tracking-widest">Recent Matches</h3>
          <button onClick={onClear} className="text-[10px] text-red-400 hover:text-red-200 uppercase tracking-wider">
             Clear History
          </button>
       </div>

       <div className="space-y-3">
         {history.map((match) => {
            const isAzureWin = match.winningTeam === 'azure';
            const isCrimsonWin = match.winningTeam === 'crimson';
            const isDraw = !match.winningTeam;

            // Determine display roles (Coach first if present in this match history)
            const displayRoles = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

            return (
              <div key={match.id} className="border border-[#1e3a5f] bg-[#05090f] clip-corner-sm transition-all hover:border-[#dcb06b]/30">
                {/* Header Summary */}
                <div 
                  className="p-4 flex items-center justify-between cursor-pointer hover:bg-[#1e3a5f]/20 transition-colors"
                  onClick={() => toggleExpand(match.id)}
                >
                   <div className="flex items-center gap-4">
                      <div className={`
                         w-2 h-12 skew-x-[-12deg]
                         ${isAzureWin ? 'bg-cyan-500 shadow-[0_0_10px_#06b6d4]' : isCrimsonWin ? 'bg-red-500 shadow-[0_0_10px_#ef4444]' : 'bg-gray-500'}
                      `}></div>
                      <div>
                         <div className="text-xs text-[#8a9db8] font-orbitron tracking-widest mb-1">
                            ROOM: {match.roomId}
                         </div>
                         <div className={`font-cinzel font-bold text-lg ${isAzureWin ? 'text-cyan-400' : isCrimsonWin ? 'text-red-500' : 'text-gray-400'}`}>
                            {isAzureWin ? 'AZURE VICTORY' : isCrimsonWin ? 'CRIMSON VICTORY' : 'MATCH ENDED'}
                         </div>
                         <div className="text-[10px] text-[#4a5f78]">{formatDate(match.timestamp)}</div>
                      </div>
                   </div>

                   <div className={`transform transition-transform duration-300 ${expandedId === match.id ? 'rotate-180' : ''}`}>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-[#dcb06b]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                      </svg>
                   </div>
                </div>

                {/* Details Accordion */}
                {expandedId === match.id && (
                  <div className="border-t border-[#1e3a5f] p-4 bg-[#0a1a2f]/30">
                     <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        {/* Azure Roster */}
                        <div>
                           <h4 className="text-cyan-500 font-cinzel text-xs tracking-widest mb-3 border-b border-cyan-500/20 pb-1">AZURE TEAM</h4>
                           <div className="space-y-2">
                              {displayRoles.map(role => {
                                 const p = match.azureTeam.find(s => s.role === role)?.player;
                                 if (!p) return null;

                                 const isMvp = match.mvpId === p.id;
                                 const rating = match.ratings?.[p.id] || 0;

                                 return (
                                    <div key={role} className="flex items-center justify-between text-sm">
                                       <span className="flex items-center gap-2 text-[#8a9db8]">
                                          <div className={`scale-90 ${role === Role.COACH ? 'text-white' : 'text-cyan-500/70'}`}>{RoleIcons[role]}</div>
                                       </span>
                                       <div className="flex items-center gap-2">
                                           {isMvp && (
                                              <span className="text-[8px] font-black bg-yellow-500 text-black px-1 rounded shadow-[0_0_5px_gold]">MVP</span>
                                           )}
                                           <span className="text-white font-orbitron">{p.name}</span>
                                           {renderRatingArrow(rating)}
                                       </div>
                                    </div>
                                 );
                              })}
                           </div>
                        </div>

                        {/* Crimson Roster */}
                        <div>
                           <h4 className="text-red-500 font-cinzel text-xs tracking-widest mb-3 border-b border-red-500/20 pb-1">CRIMSON TEAM</h4>
                           <div className="space-y-2">
                              {displayRoles.map(role => {
                                 const p = match.crimsonTeam.find(s => s.role === role)?.player;
                                 if (!p) return null;

                                 const isMvp = match.mvpId === p.id;
                                 const rating = match.ratings?.[p.id] || 0;

                                 return (
                                    <div key={role} className="flex items-center justify-between text-sm">
                                       <span className="flex items-center gap-2 text-[#8a9db8]">
                                          <div className={`scale-90 ${role === Role.COACH ? 'text-white' : 'text-red-500/70'}`}>{RoleIcons[role]}</div>
                                       </span>
                                       <div className="flex items-center gap-2">
                                           {isMvp && (
                                              <span className="text-[8px] font-black bg-yellow-500 text-black px-1 rounded shadow-[0_0_5px_gold]">MVP</span>
                                           )}
                                           <span className="text-white font-orbitron">{p.name}</span>
                                           {renderRatingArrow(rating)}
                                       </div>
                                    </div>
                                 );
                              })}
                           </div>
                        </div>
                     </div>
                  </div>
                )}
              </div>
            );
         })}
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MatchResult, TeamSlot, Role, Player, Lang } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { PortalTransition } from './PortalTransition';
import { MatchSummary } from './MatchSummary';
import { VictoryCelebration } from './VictoryCelebration';
import { EvaluationScreen } from './EvaluationScreen';

interface MatchDisplayProps {
  match: MatchResult;
  activePlayers: Player[]; 
  initialMode: 'draft' | 'battle';
  onReset: () => void; 
  onCompleteMatch: (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => void; 
  onReroll: (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => void;
  onStartBattle: () => void; 
  lang?: Lang;
}

type ViewState = 'drafting' | 'transition' | 'final' | 'celebration' | 'evaluation';

export const MatchDisplay: React.FC<MatchDisplayProps> = ({ 
  match, activePlayers, initialMode, 
  onReset, onCompleteMatch, onReroll, onStartBattle 
}) => {
  const [viewState, setViewState] = useState<ViewState>('drafting');
  const [winningTeam, setWinningTeam] = useState<'azure' | 'crimson' | null>(null);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);

  useEffect(() => {
     if (initialMode === 'battle') {
        setViewState('final');
     } else {
        setViewState('drafting');
     }
  }, [initialMode]);

  const displayRoles = match.isCoachMode ? [...ROLES_ORDER, Role.COACH] : ROLES_ORDER;
  const [currentRoleIndex, setCurrentRoleIndex] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'draft' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  const [revealedCards, setRevealedCards] = useState<Set<string>>(new Set());

  const getPlayerForRole = (team: TeamSlot[], role: Role) => {
    return team.find(slot => slot.role === role);
  };

  const getCardId = (team: 'azure' | 'crimson', role: Role) => `${team}-${role}`;

  const formatRoleLabelShort = (role: Role) => {
    switch(role) {
        case Role.CLASH: return "CLASH";
        case Role.JUNGLE: return "JUNGLE";
        case Role.MID: return "MID";
        case Role.FARM: return "FARM";
        case Role.ROAM: return "ROAM";
        case Role.COACH: return "COACH";
        default: return (role as string).toUpperCase();
    }
  };

  const handleNext = () => {
    const nextIndex = currentRoleIndex + 1;
    if (nextIndex >= displayRoles.length) return;

    const roleToReveal = displayRoles[nextIndex];

    const azureId = getCardId('azure', roleToReveal);
    if (!revealedCards.has(azureId)) {
      startWheel('azure', roleToReveal);
      return;
    }

    const crimsonId = getCardId('crimson', roleToReveal);
    if (!revealedCards.has(crimsonId)) {
      startWheel('crimson', roleToReveal);
      return;
    }
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    displayRoles.forEach(r => {
      allCards.add(getCardId('azure', r));
      allCards.add(getCardId('crimson', r));
    });
    setRevealedCards(allCards);
    setCurrentRoleIndex(displayRoles.length - 1);
  };

  const handleAbort = () => {
    if (window.confirm("Batalkan draft ini? Semua progres akan hilang.")) {
      onReset();
    }
  };

  const startWheel = (team: 'azure' | 'crimson', role: Role) => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const winner = getPlayerForRole(teamSlots, role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    match.azureTeam.forEach(slot => { if (revealedCards.has(getCardId('azure', slot.role))) revealedPlayerIds.add(slot.player.id); });
    match.crimsonTeam.forEach(slot => { if (revealedCards.has(getCardId('crimson', slot.role))) revealedPlayerIds.add(slot.player.id); });

    const candidates = activePlayers
      .filter(p => {
          if (revealedPlayerIds.has(p.id)) return false;
          if (role === Role.COACH) return p.roles.includes(Role.COACH);
          return p.isAllRoles || p.roles.includes(role);
      });

    const candidateNames = candidates.map(p => p.name);

    if (candidates.length === 1) {
        const cardId = getCardId(team, role);
        setAutoFillFlash(cardId);
        setRevealedCards(prev => new Set(prev).add(cardId));
        if (team === 'crimson') {
            setCurrentRoleIndex(prev => prev + 1);
        }
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    if (!candidateNames.includes(winner.name)) {
        candidateNames.push(winner.name);
    }

    const randomDuration = Math.floor(Math.random() * (7000 - 3000 + 1)) + 3000;

    setWheelState({
      isOpen: true,
      type: 'draft',
      team,
      role,
      winnerName: winner.name,
      candidates: candidateNames,
      duration: randomDuration
    });
  };

  const handleRerollClick = (team: 'azure' | 'crimson', role: Role) => {
    const azureIds = new Set(match.azureTeam.map(s => s.player.id));
    const crimsonIds = new Set(match.crimsonTeam.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));

    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => {
       if (role === Role.COACH) return p.roles.includes(Role.COACH);
       return p.isAllRoles || p.roles.includes(role);
    });

    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    if (candidates.length === 1) {
        onReroll(team, role, candidates[0]);
        return;
    }

    const randomDuration = 4000; 

    setWheelState({
        isOpen: true,
        type: 'reroll',
        team,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'draft') {
        const { team, role } = wheelState;
        setRevealedCards(prev => new Set(prev).add(getCardId(team, role)));
        if (team === 'crimson') setCurrentRoleIndex(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        onReroll(wheelState.team, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const handleWheelCancel = () => setWheelState(null);
  const handleInitializeBattle = () => setViewState('transition');
  const handleTransitionComplete = () => { onStartBattle(); setViewState('final'); };
  const handleMatchDecided = (winner: 'azure' | 'crimson' | null) => {
    if (winner) { setWinningTeam(winner); setViewState('celebration'); } 
    else { onCompleteMatch(null); }
  };
  const handleCelebrationDismiss = () => setViewState('evaluation');
  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => { onCompleteMatch(winningTeam, mvpId, ratings); }

  if (viewState === 'evaluation' && winningTeam) return <EvaluationScreen match={match} winner={winningTeam} onComplete={handleEvaluationComplete} />;
  if (viewState === 'celebration' && winningTeam) return <VictoryCelebration winner={winningTeam} teamSlots={winningTeam === 'azure' ? match.azureTeam : match.crimsonTeam} onDismiss={handleCelebrationDismiss} />;
  if (viewState === 'transition') return <PortalTransition azureTeam={match.azureTeam} crimsonTeam={match.crimsonTeam} onComplete={handleTransitionComplete} />;
  if (viewState === 'final') return <MatchSummary match={match} onReset={handleMatchDecided} />;

  const renderPlayerCard = (role: Role, roleIndex: number, team: 'azure' | 'crimson') => {
    const teamSlots = team === 'azure' ? match.azureTeam : match.crimsonTeam;
    const player = getPlayerForRole(teamSlots, role)?.player;
    const cardId = getCardId(team, role);
    const isRevealed = revealedCards.has(cardId);
    const isAutoFilled = autoFillFlash === cardId;
    const isCoach = role === Role.COACH;

    let theme = isCoach ? { bg: 'bg-[#1a1a1a]', border: 'border-white', glow: 'shadow-[0_0_20px_rgba(255,255,255,0.8)]', text: 'text-white', gradient: 'from-white/20 to-transparent' }
      : team === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-hok-cyan', glow: 'shadow-[0_0_10px_#00d2ff]', text: 'text-hok-cyan', gradient: 'from-[#00d2ff]/20 to-transparent' }
      : { bg: 'bg-[#1a0505]', border: 'border-hok-red', glow: 'shadow-[0_0_10px_#ef4444]', text: 'text-hok-red', gradient: 'from-[#c02d2d]/20 to-transparent' };

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-90 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    return (
      <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
        <div className={`
            absolute inset-0 clip-corner-md border-l-4 tilt-card
            ${theme.bg} ${theme.border} 
            ${isAutoFilled ? 'shadow-[0_0_30px_#dcb06b] border-[#dcb06b]' : theme.glow}
            shadow-[0_0_15px_rgba(0,0,0,0.5)]
            transition-all duration-300 hover:brightness-110
        `}>
           <div className={`flex flex-col h-full relative z-10 px-4 py-1 justify-center ${team === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-0.5 px-2 py-0.5 rounded-sm bg-black/40 border border-white/10 ${theme.text} transform transition-transform duration-500 w-auto inline-block scale-90 origin-${team === 'crimson' ? 'right' : 'left'}`}>
                {RoleIcons[role]}
             </div>
             <span className={`block text-lg md:text-xl font-bold text-white truncate font-orbitron drop-shadow-md w-full`}>
                {player?.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(team, role); }}
             className={`absolute top-1 p-1.5 bg-black/50 hover:bg-[#dcb06b] rounded-full transition-colors group-hover:opacity-100 opacity-0 text-white hover:text-black z-50 border border-white/20 ${team === 'azure' ? 'right-2' : 'left-2'}`}
             title="Ganti Pemain Slot Ini"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
           </button>
        </div>
      </div>
    );
  };

  const nextRoleIndex = currentRoleIndex + 1;
  const nextRoleName = nextRoleIndex < displayRoles.length ? displayRoles[nextRoleIndex] : null;
  const isFinished = currentRoleIndex >= displayRoles.length - 1 && revealedCards.size === (match.isCoachMode ? 12 : 10);

  let buttonText = "MULAILAH DRAFT";
  if (nextRoleName) {
     const nextTeam = !revealedCards.has(getCardId('azure', nextRoleName)) ? 'AZURE' : 'CRIMSON';
     const roleLabel = formatRoleLabelShort(nextRoleName);
     buttonText = `PILIH ${nextTeam} ${roleLabel}`;
  }

  return (
    <>
      {wheelState && wheelState.isOpen && (
        <SpinWheel 
          candidates={wheelState.candidates} 
          winnerName={wheelState.winnerName} 
          team={wheelState.team} 
          roleName={wheelState.role} 
          roomId={match.roomId} 
          duration={wheelState.duration}
          onComplete={handleWheelComplete} 
          onCancel={handleWheelCancel} 
        />
      )}
      <div className="w-full max-w-7xl mx-auto px-4 py-8 pb-32 relative">
        <div className="absolute top-4 left-4 right-4 z-40 flex justify-between">
           <Button variant="outline" size="sm" onClick={handleAbort} className="border-red-900/50 text-red-500 hover:bg-red-900/20 text-[10px] px-3">
              <span className="flex items-center gap-2">BATALKAN DRAFT</span>
           </Button>
           {!isFinished && <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-[10px] px-3">BUKA SEMUA</Button>}
        </div>

        {/* ROOM ID HIGHLIGHT - IDENTICAL TO LOBBY */}
        <div className="flex flex-col items-center mb-8 pt-8">
           <div className="flex flex-col items-center gap-1">
              <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase drop-shadow-sm mb-3">ROOM ID ACCESS</span>
              <div className="relative">
                 <div className="absolute -inset-6 bg-[#dcb06b] blur-[30px] opacity-15 animate-pulse pointer-events-none"></div>
                 <div className="relative bg-black/80 border-2 border-[#dcb06b] px-16 py-4 clip-corner-sm flex flex-col items-center shadow-[0_0_40px_rgba(220,176,107,0.3)]">
                    <span className="text-5xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_20px_#dcb06b] animate-[chromatic_0.2s_infinite]">
                      {match.roomId}
                    </span>
                 </div>
              </div>
           </div>

           <div className="flex justify-between items-center w-full relative max-w-5xl mt-12">
              <div className="w-1/3 text-center"><h2 className="text-xl md:text-4xl font-cinzel font-black text-hok-cyan drop-shadow-[0_0_10px_#00d2ff]">AZURE GOLEM</h2></div>
              <div className="w-1/3 flex justify-center"><div className="relative w-20 h-20 flex items-center justify-center"><span className="text-3xl font-black italic text-[#dcb06b] z-10 animate-pulse-fast">VS</span></div></div>
              <div className="w-1/3 text-center"><h2 className="text-xl md:text-4xl font-cinzel font-black text-hok-red drop-shadow-[0_0_10px_#ef4444]">CRIMSON GOLEM</h2></div>
           </div>
        </div>

        <div className="relative space-y-2 md:space-y-3">
          {displayRoles.map((role, idx) => (
            <div key={role} className="grid grid-cols-1 md:grid-cols-2 gap-2 md:gap-8 items-center">
               <div className="order-1 md:order-none">{renderPlayerCard(role, idx, 'azure')}</div>
               <div className="order-2 md:order-none">{renderPlayerCard(role, idx, 'crimson')}</div>
            </div>
          ))}
        </div>
        <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end bg-gradient-to-t from-[#05090f] via-[#05090f]/90 to-transparent h-48 pointer-events-none">
           <div className="pointer-events-auto">
              {!isFinished ? (
                 <button onClick={handleNext} className="group relative px-12 h-16 bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-lg hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300">
                   {buttonText}
                 </button>
              ) : (
                 <Button onClick={handleInitializeBattle} className="px-12 animate-pulse">MASUK ARENA TEMPUR</Button>
              )}
           </div>
        </div>
      </div>
    </>
  );
};

/**
 * Shared language type for localization.
 */
export type Lang = 'ID' | 'EN';

export enum Role {
  CLASH = 'Clash Lane',
  JUNGLE = 'Jungler',
  MID = 'Mid Lane',
  FARM = 'Farm Lane',
  ROAM = 'Roam',
  COACH = 'Coach',
}

export interface PlayerStats {
  matchesPlayed: number;
  wins: number;
  currentStreak: number;
  maxStreak: number;
}

export interface Player {
  id: string;
  name: string;
  roles: Role[]; 
  isAllRoles: boolean;
  isActive: boolean; // Menandakan apakah pemain ikut match kali ini
  isLastMatchMvp?: boolean; // Tracks if player was MVP in the specific last match
  lastMatchRating?: number; // New: Performa evaluasi terakhir (-2 s/d 2)
  stats: PlayerStats;
}

export interface TeamSlot {
  role: Role;
  player: Player;
}

export interface MatchResult {
  roomId: string;
  azureTeam: TeamSlot[];
  crimsonTeam: TeamSlot[];
  isCoachMode: boolean;
  timestamp: number;
}

export interface MatchHistoryEntry extends MatchResult {
  id: string;
  winningTeam: 'azure' | 'crimson' | null; // null means draw or abandoned
  mvpId?: string; // Track who was MVP in history
  ratings?: Record<string, number>; // 2 (Excellent), 1 (Good), -1 (Bad), -2 (Very Bad)
  durationSeconds?: number; // New: Session duration from evaluation
}

