  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

type ViewMode = 'lobby' | 'match' | 'battle';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');
  const [lang, setLang] = useState<Lang>('ID');
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [matchCount, setMatchCount] = useState(1);
  const [showWelcome, setShowWelcome] = useState(true);

  const t = {
    ID: {
      presence: "Kehadiran Squad",
      roster: "Daftar Tempur",
      history: "Arsip Pertempuran",
      generate: "MULAILAH DRAFT",
      quickFill: "Isi Cepat",
      roomAccess: "AKSES ROOM ID",
      wipe: "Hapus Data",
      coachActive: "STRATEGI COACH: AKTIF",
      coachInactive: "STRATEGI COACH: NONAKTIF",
      errorRoom: "Tentukan Room ID!",
      errorPlayers: (req: number) => `Butuh minimal ${req} pemain AKTIF.`,
      footer: "PROJECT DIKEMBANGKAN UNTUK KEPERLUAN CUSTOM MATCH HONOR OF KINGS DISCORD INDONESIA."
    },
    EN: {
      presence: "Squad Presence",
      roster: "Combatant Roster",
      history: "Battle Archives",
      generate: "START BATTLE DRAFT",
      quickFill: "Quick Fill",
      roomAccess: "ROOM ID ACCESS",
      wipe: "Wipe Data",
      coachActive: "COACH STRATEGY: ACTIVE",
      coachInactive: "COACH STRATEGY: INACTIVE",
      errorRoom: "Assign Room ID!",
      errorPlayers: (req: number) => `Need at least ${req} ACTIVE players.`,
      footer: "PROJECT DEVELOPED FOR HONOR OF KINGS DISCORD INDONESIA CUSTOM MATCHES."
    }
  }[lang];

  const navigate = useCallback((mode: ViewMode, data: any) => {
    setViewMode(mode);
    if (mode === 'lobby' && Array.isArray(data)) setPlayers(data);
    else if ((mode === 'match' || mode === 'battle') && data) setCurrentMatch(data);
  }, []);

  const handleBatchProcess = (batchData: any[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], roles: item.roles, isAllRoles: item.isAllRoles, isActive: true };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };
  const handleUpdatePlayer = (updatedPlayer: Player) => setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) { setErrorMsg(t.errorRoom); return; }
    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) { setErrorMsg(t.errorPlayers(required)); return; }
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) { setCurrentMatch(result); setErrorMsg(null); navigate('match', result); }
    else { setErrorMsg(lang === 'ID' ? "Komposisi tim gagal." : "Failed to find composition."); }
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>, durationSeconds?: number) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings, durationSeconds };
    setMatchHistory(prev => [historyEntry, ...prev]);
    const updatedPlayers = players.map(p => {
      const isMvp = mvpId === p.id;
      const matchPlayer = [...currentMatch.azureTeam, ...currentMatch.crimsonTeam].find(s => s.player.id === p.id);
      if (!matchPlayer) return { ...p, isLastMatchMvp: false };
      const isAzure = currentMatch.azureTeam.some(s => s.player.id === p.id);
      const isWinner = winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson'));
      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };
      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }
      return { ...p, stats: newStats, isLastMatchMvp: isMvp, lastMatchRating: ratings?.[p.id] || 0 };
    });
    setPlayers(updatedPlayers); setMatchCount(prev => prev + 1); setShowWelcome(true); navigate('lobby', updatedPlayers); setCurrentMatch(null); setRoomId('');
  };

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const batchData = shuffledHeroes.slice(0, 15).map(hero => ({ name: hero.name, roles: hero.roles, isAllRoles: false, action: 'add' as const }));
     for(let i=0; i<5; i++) batchData.push({ name: `Player ${i+1}`, roles: [], isAllRoles: true, action: 'add' });
     if (isCoachMode) {
        batchData.push({ name: "Coach HoK", roles: [Role.COACH], isAllRoles: false, action: 'add' });
        batchData.push({ name: "Coach Global", roles: [Role.COACH], isAllRoles: false, action: 'add' });
     }
     handleBatchProcess(batchData);
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <WibClock />
      <WelcomeModal isOpen={showWelcome} onClose={() => setShowWelcome(false)} matchNumber={matchCount} lastWinner={matchHistory[0]?.winningTeam || null} lang={lang} />

      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/95 via-[#05090f]/70 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />}

      {viewMode === 'lobby' && (
        <>
          <nav className="relative z-50 flex justify-end p-4 max-w-7xl mx-auto w-full">
            <div className="flex bg-[#0a1a2f]/80 border border-[#dcb06b]/30 p-1 clip-corner-sm">
               <button onClick={() => setLang('ID')} className={`px-4 py-1 text-xs font-bold transition-all ${lang === 'ID' ? 'bg-[#dcb06b] text-black' : 'text-[#8a9db8] hover:text-[#dcb06b]'}`}>ID</button>
               <div className="w-[1px] bg-[#dcb06b]/20"></div>
               <button onClick={() => setLang('EN')} className={`px-4 py-1 text-xs font-bold transition-all ${lang === 'EN' ? 'bg-[#dcb06b] text-black' : 'text-[#8a9db8] hover:text-[#dcb06b]'}`}>EN</button>
            </div>
          </nav>

          <main className="relative z-10 pt-4 px-4 flex-grow max-w-7xl mx-auto w-full">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
              <div className={`lg:col-span-4 space-y-4 ${isSidebarOpen ? '' : 'hidden'}`}>
                <div className="relative group">
                  <div className="absolute -inset-[1px] bg-[#dcb06b]/50 clip-corner-md opacity-30"></div>
                  <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative flex flex-col items-center">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-3">{t.roomAccess}</span>
                    <div className="relative w-full">
                      <div className="relative bg-black/60 border border-[#dcb06b]/30 py-4 px-4 clip-corner-sm flex flex-col items-center">
                         <input type="text" value={roomId} onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} placeholder="0000" className={`bg-transparent text-5xl font-orbitron font-black w-full text-center focus:outline-none tracking-[0.4em] transition-all duration-300 ${roomId ? 'text-white drop-shadow-[0_0_15px_#dcb06b] animate-[chromatic_0.2s_infinite]' : 'text-[#1e3a5f]'}`}/>
                      </div>
                    </div>
                  </div>
                </div>

                <button onClick={() => setIsCoachMode(!isCoachMode)} className="relative w-full group overflow-hidden p-[1px] clip-corner-sm">
                   <div className={`relative z-10 py-4 px-6 flex items-center justify-center transition-all duration-300 clip-corner-sm border ${isCoachMode ? 'bg-[#dcb06b]/10 border-[#dcb06b] text-[#dcb06b]' : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}`}>
                      <span className={`font-cinzel font-black text-xs tracking-[0.2em] uppercase ${isCoachMode ? 'text-white drop-shadow-[0_0_8px_#dcb06b]' : ''}`}>{isCoachMode ? t.coachActive : t.coachInactive}</span>
                   </div>
                </button>

                <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} lang={lang} />
                <div className="relative p-6 clip-corner-md bg-[#0a1a2f]/80 backdrop-blur-md border border-[#1e3a5f]">
                   <div className="flex justify-between items-end mb-6">
                      <div className="flex flex-col">
                         <span className="text-[#8a9db8] text-[9px] uppercase font-bold tracking-widest mb-1">{t.presence}</span>
                         <div className="flex items-baseline gap-2">
                            <span className="text-4xl font-orbitron font-bold text-white">{activePlayers.length}</span>
                            <span className="text-sm font-orbitron text-[#4a5f78]">/ {players.length}</span>
                         </div>
                      </div>
                      <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b]/30 px-3 py-1.5 hover:bg-[#dcb06b] hover:text-black transition-all clip-corner-sm uppercase font-bold">{t.quickFill}</button>
                   </div>
                   {errorMsg && <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/40 text-red-200 text-[10px] font-bold uppercase">{errorMsg}</div>}
                   <Button onClick={handleGenerate} className="w-full">{t.generate}</Button>
                </div>
              </div>

              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex items-center justify-between mb-4 bg-black/40 p-4 border border-[#1e3a5f] clip-corner-sm">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 border border-[#1e3a5f] text-[#dcb06b] hover:border-[#dcb06b] transition-all">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
                    </button>
                    <h2 className="text-xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase">{t.roster}</h2>
                    <button onClick={() => { if(window.confirm(lang === 'ID' ? "Hapus semua?" : "Clear all?")) setPlayers([]); }} className="text-[10px] text-[#4a5f78] hover:text-red-400 uppercase font-bold tracking-tighter transition-colors">{t.wipe}</button>
                 </div>
                 <div className="p-6 bg-[#05090f]/90 clip-corner-md min-h-[500px]">
                    <PlayerList players={players} onRemove={removePlayer} onToggleActive={togglePlayerActive} onEdit={handleEditPlayer} isSidebarOpen={isSidebarOpen} lang={lang} />
                 </div>
                 <div className="mt-8 p-6 bg-black/40 border border-[#1e3a5f] clip-corner-sm">
                    <h2 className="text-xl font-cinzel font-black text-[#dcb06b] mb-6 tracking-widest uppercase">{t.history}</h2>
                    <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} lang={lang} />
                 </div>
              </div>
            </div>
          </main>

          <footer className="py-12 px-6 text-center border-t border-[#dcb06b]/5 bg-black/80 mt-12">
              <div className="max-w-4xl mx-auto flex flex-col items-center gap-3">
                  <div className="text-[#dcb06b] font-cinzel font-black text-[10px] tracking-[0.4em] mb-1 uppercase leading-loose">
                      EST. 2025 // APP DEVELOPED BY KAZEHUNT
                  </div>
                  <div className="text-[#1e3a5f] font-orbitron text-[8px] leading-relaxed tracking-[0.2em] uppercase max-w-2xl">
                      {t.footer}
                  </div>
              </div>
          </footer>
        </>
      )}

      {currentMatch && viewMode !== 'lobby' && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={() => { setCurrentMatch(null); setViewMode('lobby'); }}
          onCompleteMatch={handleMatchFinish}
          onReroll={(team, role, p) => {
             if (!currentMatch) return;
             const updated = {
                ...currentMatch,
                azureTeam: currentMatch.azureTeam.map(s => (team === 'azure' && s.role === role) ? { ...s, player: p } : s),
                crimsonTeam: currentMatch.crimsonTeam.map(s => (team === 'crimson' && s.role === role) ? { ...s, player: p } : s)
             };
             setCurrentMatch(updated);
          }}
          onStartBattle={() => setViewMode('battle')}
          lang={lang}
        />
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role, Lang } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
  lang?: Lang;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;

    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400 items-center justify-center">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500 items-center justify-center">
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  const gridClasses = isSidebarOpen ? "grid-cols-1 md:grid-cols-2 lg:grid-cols-3" : "grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => setFilter(val as FilterType)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-3 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';
          let primaryColor = '';

          if (player.isActive) {
            if (isMvp && !isCoach) {
              primaryColor = '#fbbf24'; 
              glowColor = 'drop-shadow-[0_0_12px_#fbbf24]';
            } else if (isCoach) {
              primaryColor = '#ffffff'; 
              glowColor = 'drop-shadow-[0_0_12px_rgba(255,255,255,0.6)]';
            } else if (ws >= 2) {
              if (ws >= 5) primaryColor = '#ef4444'; 
              else if (ws >= 4) primaryColor = '#f97316'; 
              else if (ws >= 3) primaryColor = '#a855f7'; 
              else primaryColor = '#00d2ff'; 

              glowColor = `drop-shadow-[0_0_10px_${primaryColor}]`;
            }

            if (primaryColor) {
               animationLayer = (
                 <div 
                   className="absolute inset-[-150%] animate-[spin_4s_linear_infinite]"
                   style={{
                     background: `conic-gradient(from 0deg, ${primaryColor} 0deg, ${primaryColor} 40deg, transparent 40deg, transparent 180deg, ${primaryColor} 180deg, ${primaryColor} 220deg, transparent 220deg, transparent 360deg)`
                   }}
                 />
               );
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]/20">
                 {animationLayer}
              </div>

              <div className={`absolute inset-[2px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/80 grayscale backdrop-blur-sm'}`}>

                {!player.isActive && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center pointer-events-none overflow-hidden">
                        <div className="absolute inset-0 bg-red-900/10 mix-blend-overlay"></div>
                        <div className="rotate-[-15deg] border-4 border-red-600/80 px-4 py-1 text-red-600/90 font-black text-2xl tracking-[0.3em] uppercase bg-black/40 backdrop-blur-sm shadow-[0_0_20px_rgba(220,38,38,0.4)] animate-pulse-fast">
                            BENCHED
                        </div>
                    </div>
                )}

                <div className="flex justify-between items-start mb-2 relative z-10">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp && !isCoach ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && !isCoach && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase ${getRoleBadgeStyle(r)}`}>{r.split(' ')[0]}</span>)
                      )}
                    </div>
                  </div>

                  <div className="flex flex-col items-end gap-1">
                    <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b] mb-1">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg>
                    </button>

                    {!isCoach && (
                      <div className="flex flex-col gap-1 items-end">
                         {isMvp && player.isActive && (
                           <div className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter bg-[#fbbf24] text-black clip-corner-sm shadow-[0_0_8px_rgba(251,191,36,0.6)]">
                              MVP
                           </div>
                         )}

                         {ws >= 2 && player.isActive && (
                           <div 
                             className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter text-white clip-corner-sm shadow-md"
                             style={{ backgroundColor: primaryColor }}
                           >
                              {ws} WS
                           </div>
                         )}
                      </div>
                    )}
                  </div>
                </div>

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1 relative z-10">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => onToggleActive(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => onEdit(players.find(p => p.id === menuOpenId)!)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => onRemove(menuOpenId)} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};

import React from 'react';
import { MatchResult, TeamSlot, Role } from '../types';
import { ROLES_ORDER, RoleIcons } from '../constants';
import { Button } from './Button';

interface MatchSummaryProps {
  match: MatchResult;
  onReset: (winner: 'azure' | 'crimson' | null) => void;
}

