                <h2 className="text-xl md:text-4xl font-cinzel font-black text-hok-cyan drop-shadow-[0_0_15px_#00d2ff] mb-8 text-left uppercase">
                   AZURE GOLEM
                </h2>
                <div className="space-y-4">
                   {ROLES_ORDER.map((role) => {
                      const player = getPlayer(match.azureTeam, role);
                      return (
                        <div key={role} className="flex items-center gap-4 group">
                           <div className="shrink-0 flex items-center justify-center w-32 py-1.5 bg-[#05090f] border border-cyan-500/30 rounded text-cyan-500 group-hover:bg-cyan-500 group-hover:text-black transition-colors">
                              {RoleIcons[role]}
                           </div>
                           <div className="min-w-0">
                              <div className="text-2xl font-orbitron text-white truncate font-bold">{player?.name}</div>
                           </div>
                        </div>
                      );
                   })}
                </div>
             </div>

             {/* VS DIVIDER */}
             <div className="relative z-20 flex items-center justify-center shrink-0 my-4 lg:my-0 lg:-mx-8">
                <div className="relative w-24 h-24 lg:w-32 lg:h-32 flex items-center justify-center">
                   <div className="absolute inset-0 bg-[#dcb06b] rotate-45 opacity-20 blur-xl animate-pulse"></div>
                   <div className="absolute inset-0 border-4 border-[#dcb06b] rotate-45 bg-[#05090f] shadow-lg"></div>
                   <span className="text-4xl lg:text-5xl font-black italic text-[#dcb06b] font-orbitron z-10 pr-1 pt-1 drop-shadow-[0_0_10px_#dcb06b]">VS</span>
                </div>
             </div>

             {/* CRIMSON TEAM */}
             <div className="flex-1 bg-gradient-to-l from-[#1a0505]/80 to-transparent p-8 border-r-4 border-red-500 clip-corner-md text-right shadow-[0_0_30px_rgba(239,68,68,0.1)]">
                <h2 className="text-xl md:text-4xl font-cinzel font-black text-hok-red drop-shadow-[0_0_15px_#ef4444] mb-8 uppercase">
                   CRIMSON GOLEM
                </h2>
