                           <div className="shrink-0 flex items-center justify-center w-32 py-1.5 bg-[#05090f] border border-red-500/30 rounded text-red-500 group-hover:bg-red-500 group-hover:text-black transition-colors">
                              {RoleIcons[role]}
                           </div>
                           <div className="min-w-0">
                              <div className="text-2xl font-orbitron text-white truncate font-bold">{player?.name}</div>
                           </div>
