          <div className="mt-16 flex flex-col items-center gap-4">
             <div className="text-[#dcb06b] uppercase tracking-[0.5em] text-xs font-bold mb-2 opacity-60">Declare Winner & Save History</div>

             <div className="flex flex-wrap justify-center gap-6">
                <button 
                  onClick={() => onReset('azure')}
                  className="group relative px-12 py-4 bg-[#0a1a2f] border-2 border-cyan-500 clip-corner-sm hover:bg-cyan-900/50 transition-all duration-300 overflow-hidden"
                >
                   <div className="absolute inset-0 bg-cyan-400/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                   <span className="relative z-10 font-cinzel font-black text-xl text-cyan-400 group-hover:text-white tracking-widest">
