  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

type ViewMode = 'lobby' | 'match' | 'battle';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');
  const [lang, setLang] = useState<Lang>('ID');
  const [players, setPlayers] = useState<Player[]>([]);
  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>([]);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [matchCount, setMatchCount] = useState(1);
  const [showWelcome, setShowWelcome] = useState(true);

  const t = {
    ID: {
      presence: "Kehadiran Squad",
      roster: "Daftar Tempur",
      history: "Arsip Pertempuran",
      generate: "MULAILAH DRAFT",
      quickFill: "Isi Cepat",
      roomAccess: "AKSES ROOM ID",
      wipe: "Hapus Data",
      coachActive: "STRATEGI COACH: AKTIF",
      coachInactive: "STRATEGI COACH: NONAKTIF",
      errorRoom: "Tentukan Room ID!",
      errorPlayers: (req: number) => `Butuh minimal ${req} pemain AKTIF.`,
      footer: "PROJECT DIKEMBANGKAN UNTUK KEPERLUAN CUSTOM MATCH HONOR OF KINGS DISCORD INDONESIA."
    },
    EN: {
      presence: "Squad Presence",
      roster: "Combatant Roster",
      history: "Battle Archives",
      generate: "START BATTLE DRAFT",
      quickFill: "Quick Fill",
      roomAccess: "ROOM ID ACCESS",
      wipe: "Wipe Data",
      coachActive: "COACH STRATEGY: ACTIVE",
      coachInactive: "COACH STRATEGY: INACTIVE",
      errorRoom: "Assign Room ID!",
      errorPlayers: (req: number) => `Need at least ${req} ACTIVE players.`,
      footer: "PROJECT DEVELOPED FOR HONOR OF KINGS DISCORD INDONESIA CUSTOM MATCHES."
    }
  }[lang];

  const navigate = useCallback((mode: ViewMode, data: any) => {
    setViewMode(mode);
    if (mode === 'lobby' && Array.isArray(data)) setPlayers(data);
    else if ((mode === 'match' || mode === 'battle') && data) setCurrentMatch(data);
  }, []);

  const handleBatchProcess = (batchData: any[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], roles: item.roles, isAllRoles: item.isAllRoles, isActive: true };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };
  const handleUpdatePlayer = (updatedPlayer: Player) => setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    if (!roomId.trim()) { setErrorMsg(t.errorRoom); return; }
    const required = isCoachMode ? 12 : 10;
    if (activePlayers.length < required) { setErrorMsg(t.errorPlayers(required)); return; }
    const result = generateMatch(activePlayers, roomId, isCoachMode);
    if (result) { setCurrentMatch(result); setErrorMsg(null); navigate('match', result); }
    else { setErrorMsg(lang === 'ID' ? "Komposisi tim gagal." : "Failed to find composition."); }
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>, durationSeconds?: number) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings, durationSeconds };
    setMatchHistory(prev => [historyEntry, ...prev]);
    const updatedPlayers = players.map(p => {
      const isMvp = mvpId === p.id;
      const matchPlayer = [...currentMatch.azureTeam, ...currentMatch.crimsonTeam].find(s => s.player.id === p.id);
      if (!matchPlayer) return { ...p, isLastMatchMvp: false };
      const isAzure = currentMatch.azureTeam.some(s => s.player.id === p.id);
      const isWinner = winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson'));
      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };
      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }
      return { ...p, stats: newStats, isLastMatchMvp: isMvp, lastMatchRating: ratings?.[p.id] || 0 };
    });
    setPlayers(updatedPlayers); setMatchCount(prev => prev + 1); setShowWelcome(true); navigate('lobby', updatedPlayers); setCurrentMatch(null); setRoomId('');
  };

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const batchData = shuffledHeroes.slice(0, 15).map(hero => ({ name: hero.name, roles: hero.roles, isAllRoles: false, action: 'add' as const }));
     for(let i=0; i<5; i++) batchData.push({ name: `Player ${i+1}`, roles: [], isAllRoles: true, action: 'add' });
     if (isCoachMode) {
        batchData.push({ name: "Coach HoK", roles: [Role.COACH], isAllRoles: false, action: 'add' });
        batchData.push({ name: "Coach Global", roles: [Role.COACH], isAllRoles: false, action: 'add' });
     }
     handleBatchProcess(batchData);
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <WibClock />
      <WelcomeModal isOpen={showWelcome} onClose={() => setShowWelcome(false)} matchNumber={matchCount} lastWinner={matchHistory[0]?.winningTeam || null} lang={lang} />

      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/95 via-[#05090f]/70 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />}

      {viewMode === 'lobby' && (
        <>
          <nav className="relative z-50 flex justify-end p-4 max-w-7xl mx-auto w-full">
            <div className="flex bg-[#0a1a2f]/80 border border-[#dcb06b]/30 p-1 clip-corner-sm">
               <button onClick={() => setLang('ID')} className={`px-4 py-1 text-xs font-bold transition-all ${lang === 'ID' ? 'bg-[#dcb06b] text-black' : 'text-[#8a9db8] hover:text-[#dcb06b]'}`}>ID</button>
               <div className="w-[1px] bg-[#dcb06b]/20"></div>
               <button onClick={() => setLang('EN')} className={`px-4 py-1 text-xs font-bold transition-all ${lang === 'EN' ? 'bg-[#dcb06b] text-black' : 'text-[#8a9db8] hover:text-[#dcb06b]'}`}>EN</button>
            </div>
          </nav>

          <main className="relative z-10 pt-4 px-4 flex-grow max-w-7xl mx-auto w-full">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
              <div className={`lg:col-span-4 space-y-4 ${isSidebarOpen ? '' : 'hidden'}`}>
                <div className="relative group">
                  <div className="absolute -inset-[1px] bg-[#dcb06b]/50 clip-corner-md opacity-30"></div>
                  <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative flex flex-col items-center">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-3">{t.roomAccess}</span>
                    <div className="relative w-full">
                      <div className="relative bg-black/60 border border-[#dcb06b]/30 py-4 px-4 clip-corner-sm flex flex-col items-center">
                         <input type="text" value={roomId} onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} placeholder="0000" className={`bg-transparent text-5xl font-orbitron font-black w-full text-center focus:outline-none tracking-[0.4em] transition-all duration-300 ${roomId ? 'text-white drop-shadow-[0_0_15px_#dcb06b] animate-[chromatic_0.2s_infinite]' : 'text-[#1e3a5f]'}`}/>
                      </div>
                    </div>
                  </div>
                </div>

                <button 
                  onClick={() => setIsCoachMode(!isCoachMode)} 
                  className={`
                    relative w-full group overflow-hidden p-[1.5px] clip-corner-sm transition-all duration-500
                    ${isCoachMode ? 'shadow-[0_0_20px_rgba(220,176,107,0.4)]' : ''}
                  `}
                >
                  {/* ANIMATED TRACE BORDER (Gold) */}
                  {isCoachMode && (
                    <div className="absolute inset-[-100%] animate-border-trace bg-[conic-gradient(from_0deg,transparent,transparent,#dcb06b,transparent,transparent,#f3dcb1,transparent,transparent,#dcb06b)] z-0"></div>
                  )}

                  <div className={`
                    relative z-10 py-4 px-6 flex items-center justify-center transition-all duration-300 clip-corner-sm 
                    ${isCoachMode 
                      ? 'bg-[#0a1a2f]/95 text-[#dcb06b]' 
                      : 'bg-[#0a1a2f]/80 border border-[#1e3a5f] text-[#4a5f78]'}
                  `}>
                    <span className={`
                      font-cinzel font-black text-xs tracking-[0.2em] uppercase transition-all duration-500
                      ${isCoachMode ? 'text-white drop-shadow-[0_0_8px_#dcb06b] scale-105' : ''}
                    `}>
                      {isCoachMode ? t.coachActive : t.coachInactive}
                    </span>
                  </div>
                </button>

                <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} lang={lang} />
                <div className="relative p-6 clip-corner-md bg-[#0a1a2f]/80 backdrop-blur-md border border-[#1e3a5f]">
                   <div className="flex justify-between items-end mb-6">
                      <div className="flex flex-col">
                         <span className="text-[#8a9db8] text-[9px] uppercase font-bold tracking-widest mb-1">{t.presence}</span>
                         <div className="flex items-baseline gap-2">
                            <span className="text-4xl font-orbitron font-bold text-white">{activePlayers.length}</span>
                            <span className="text-sm font-orbitron text-[#4a5f78]">/ {players.length}</span>
                         </div>
                      </div>
                      <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b]/30 px-3 py-1.5 hover:bg-[#dcb06b] hover:text-black transition-all clip-corner-sm uppercase font-bold">{t.quickFill}</button>
                   </div>
                   {errorMsg && <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/40 text-red-200 text-[10px] font-bold uppercase">{errorMsg}</div>}
                   <Button onClick={handleGenerate} className="w-full">{t.generate}</Button>
                </div>
              </div>

              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex items-center justify-between mb-4 bg-black/40 p-4 border border-[#1e3a5f] clip-corner-sm">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 border border-[#1e3a5f] text-[#dcb06b] hover:border-[#dcb06b] transition-all">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
                    </button>
                    <h2 className="text-xl font-cinzel font-black text-[#dcb06b] tracking-widest uppercase">{t.roster}</h2>
                    <button onClick={() => { if(window.confirm(lang === 'ID' ? "Hapus semua?" : "Clear all?")) setPlayers([]); }} className="text-[10px] text-[#4a5f78] hover:text-red-400 uppercase font-bold tracking-tighter transition-colors">{t.wipe}</button>
                 </div>
                 <div className="p-6 bg-[#05090f]/90 clip-corner-md min-h-[500px]">
                    <PlayerList players={players} onRemove={removePlayer} onToggleActive={togglePlayerActive} onEdit={handleEditPlayer} isSidebarOpen={isSidebarOpen} lang={lang} />
                 </div>
                 <div className="mt-8 p-6 bg-black/40 border border-[#1e3a5f] clip-corner-sm">
                    <h2 className="text-xl font-cinzel font-black text-[#dcb06b] mb-6 tracking-widest uppercase">{t.history}</h2>
                    <HistoryList history={matchHistory} onClear={() => setMatchHistory([])} lang={lang} />
                 </div>
              </div>
            </div>
          </main>

          <footer className="py-12 px-6 text-center border-t border-[#dcb06b]/5 bg-black/80 mt-12">
              <div className="max-w-4xl mx-auto flex flex-col items-center gap-3">
                  <div className="text-[#dcb06b] font-cinzel font-black text-[10px] tracking-[0.4em] mb-1 uppercase leading-loose">
                      EST. 2025 // APP DEVELOPED BY KAZEHUNT
                  </div>
                  <div className="text-[#1e3a5f] font-orbitron text-[8px] leading-relaxed tracking-[0.2em] uppercase max-w-2xl">
                      {t.footer}
                  </div>
              </div>
          </footer>
        </>
      )}

      {currentMatch && viewMode !== 'lobby' && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={() => { setCurrentMatch(null); setViewMode('lobby'); }}
          onCompleteMatch={handleMatchFinish}
          onReroll={(team, role, p) => {
             if (!currentMatch) return;
             const updated = {
                ...currentMatch,
                azureTeam: currentMatch.azureTeam.map(s => (team === 'azure' && s.role === role) ? { ...s, player: p } : s),
                crimsonTeam: currentMatch.crimsonTeam.map(s => (team === 'crimson' && s.role === role) ? { ...s, player: p } : s)
             };
             setCurrentMatch(updated);
          }}
          onStartBattle={() => setViewMode('battle')}
          lang={lang}
        />
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry, Lang } from './types';
import { PlayerForm } from './components/PlayerForm';
